INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-alcatraz', 'alcatraz', 'www.alcatraz.ai', 'https://www.alcatraz.ai', 'Alcatraz', 'Privacy-focused facial authentication for physical access control and tailgating detection.', 'The clever bet is that AI data centers need a better lock, not another badge reader. Alcatraz turns Face ID into building access with Rock X, edge authentication, 3D liveness, tailgating detection, and opt-in enrollment; it says 5M employees are protected. Unlike surveillance-first facial recognition, the pitch is authentication that forgets the face after the door opens. The risk is whether buyers trust the privacy distinction once regulators get involved.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.alcatraz.ai", "type": "official"}, {"id": "funding_1", "label": "Alcatraz", "url": "https://www.alcatraz.ai/press-release/alcatraz-raises-50-million-series-b", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Alcatraz: Privacy-focused facial authentication for physical access control and tailgating detection.", "source_ids": ["official_site"]}, {"claim": "Alcatraz turns Face ID into building access with Rock X, edge authentication, 3D liveness, tailgating detection, and opt-in enrollment; it says 5M employees are protected.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "Face ID for secure buildings", "why_now": "Recent source-backed funding and public product evidence make physical security, biometrics, ai infrastructure worth tracking."}, "risks": [{"claim": "The risk is whether buyers trust the privacy distinction once regulators get involved.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Face ID for secure buildings', 'Other', 'Series B', '$50M', NULL, NULL, NULL, 'US', 'physical security,biometrics,ai infrastructure,access control', 'BlackPeak Capital', NULL, 1, 'alcatraz.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-all3', 'all3', 'www.all3.com', 'https://www.all3.com', 'All3', 'AI design, robotic fabrication, and on-site assembly for buildings.', 'Construction robotics usually breaks between design software and the job site. Unlike prefab software, All3 is trying the harder route: AI-generated architecture, real-time fabrication software, timber components, and Mantis robots that install, fasten, finish, and inspect on site. The public pages claim 100+ in-house engineers and a cost-your-project flow, while TNW reports 100,000+ square meters processed for Germany. The risk is whether vertical integration survives permits and messy sites.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.all3.com", "type": "official"}, {"id": "funding_1", "label": "TNW", "url": "https://thenextweb.com/news/all3-25m-seed-construction-robots-ai-housing", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes All3: AI design, robotic fabrication, and on-site assembly for buildings.", "source_ids": ["official_site"]}, {"claim": "VentureDex product review notes that unlike prefab software, All3 is trying the harder route: AI-generated architecture, real-time fabrication software, timber components, and Mantis robots that install, fasten, finish, and inspect on site.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$25M Seed for construction robots", "why_now": "Recent source-backed funding and public product evidence make construction robotics, physical ai, robotic manufacturing worth tracking."}, "risks": [{"claim": "The risk is whether vertical integration survives permits and messy sites.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$25M Seed for construction robots', 'AI / ML', 'Seed', '$25M', NULL, NULL, NULL, 'Europe', 'construction robotics,physical ai,robotic manufacturing,housing', 'RTP Global', '{"linkedin": "https://www.linkedin.com/company/all3"}', 1, 'all3.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-allo', 'allo', 'allo.restaurant', 'https://allo.restaurant/', 'allO', 'Restaurant operating system for POS, reservations, ordering, inventory, and payments.', 'The smart move is treating restaurant software as one floor plan instead of twenty tabs. allO shows POS, reservations, kitchen monitor, scan-to-order, webshop, delivery, inventory, payments, and an app login for German restaurants. Unlike generic POS suites, it narrows the workflow to table service, hotpot, buffets, and kitchen handoffs, with claims like 30% faster service.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://allo.restaurant/", "type": "official"}, {"id": "funding_1", "label": "Dealroom.co", "url": "https://app.dealroom.co/news/feed/allo-raises-14m-series-a-led-by-zigg-capital-to-scale-ai-native-restaurant-operating-system-across-europe", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes allO: Restaurant operating system for POS, reservations, ordering, inventory, and payments.", "source_ids": ["official_site"]}, {"claim": "allO shows POS, reservations, kitchen monitor, scan-to-order, webshop, delivery, inventory, payments, and an app login for German restaurants.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Restaurant OS with POS depth", "why_now": "Recent source-backed funding and public product evidence make restaurants, pos, inventory worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Restaurant OS with POS depth', 'SaaS', 'Series A', '$14M', NULL, NULL, NULL, 'Europe', 'restaurants,pos,inventory,payments,operations', 'Zigg Capital', NULL, 1, 'allo.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-amperos', 'amperos', 'www.amperos.com', 'https://www.amperos.com', 'Amperos', 'AI denial management and insurance collections for providers.', 'Denial management usually dies in workqueues; this tries to make it an owned operating system. Amperos works claims from submission to payment, with AI agents handling payor portals, calls, corrected claims, records, and appeals while RCM specialists cover hard cases. Unlike tools that only draft letters or make calls, the bet is full workflow ownership, visible in 500,000+ claims and 3,000 clinical locations. The risk is healthcare edge cases pulling humans back into the loop.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.amperos.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/amperos-health-secures-16m-investment-as-it-launches-industrys-first-ai-native-denial-management-and-revenue-recovery-platform-302749446.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Amperos: AI denial management and insurance collections for providers.", "source_ids": ["official_site"]}, {"claim": "Amperos works claims from submission to payment, with AI agents handling payor portals, calls, corrected claims, records, and appeals while RCM specialists cover hard cases.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "$16M Series A for AI denials", "why_now": "Recent source-backed funding and public product evidence make healthcare ai, denial management, revenue cycle worth tracking."}, "risks": [{"claim": "The risk is healthcare edge cases pulling humans back into the loop.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$16M Series A for AI denials', 'HealthTech', 'Series A', '$16M', NULL, NULL, NULL, 'US', 'healthcare ai,denial management,revenue cycle,claims', 'Bessemer Venture Partners, Uncork Capital, Neo', '{"linkedin": "https://www.linkedin.com/company/amperos-health"}', 1, 'amperos.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-arkeus', 'arkeus', 'arkeus.com', 'https://arkeus.com/products/the-warden', 'Arkeus', 'AI hyperspectral sensing systems for autonomous defense platforms.', 'The wager is visual intelligence for drones that can see when ordinary cameras give up. Arkeus exposes WARDEN, HSOR, S-HSOR, and optical terminal guidance, and says its sensors detected targets up to 8x farther in degraded conditions. Unlike generic autonomy software, the product bet is a sensing layer built for edge ISR. The public surface is thinner than the defense contracts, but the technical wedge is sharp.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://arkeus.com/products/the-warden", "type": "official"}, {"id": "funding_1", "label": "Arkeus", "url": "https://arkeus.com/news/tectonic-defense-covers-arkeus-series-a-and-the-technology-giving-autonomous-systems-a-sixth-sense", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Arkeus: AI hyperspectral sensing systems for autonomous defense platforms.", "source_ids": ["official_site"]}, {"claim": "Arkeus exposes WARDEN, HSOR, S-HSOR, and optical terminal guidance, and says its sensors detected targets up to 8x farther in degraded conditions.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "8x range in degraded vision", "why_now": "Recent source-backed funding and public product evidence make defense tech, hyperspectral sensing, autonomy worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '8x range in degraded vision', 'AI / ML', 'Series A', '$18M', NULL, NULL, NULL, 'Global / Remote', 'defense tech,hyperspectral sensing,autonomy,edge ai', 'QIC Ventures', NULL, 1, 'arkeus.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-balerion', 'balerion', 'balerion.ai', 'https://balerion.ai', 'Balerion', 'AI loan-intelligence platform for mortgage origination.', 'The smart move is starting where mortgage files actually break: income math, missing documents, NSF flags, and Fannie/Freddie overlays. Balerion Loan Intelligence is already used by FM Home Loans, a lender managing $2B+ in loan volume, and embeds into existing origination workflows. Unlike point AI tools, it wants to reason across the whole loan file. The risk is enterprise pilots turning into custom services.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://balerion.ai", "type": "official"}, {"id": "funding_1", "label": "Balerion", "url": "https://balerion.ai/press", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Balerion: AI loan-intelligence platform for mortgage origination.", "source_ids": ["official_site"]}, {"claim": "Balerion Loan Intelligence is already used by FM Home Loans, a lender managing $2B+ in loan volume, and embeds into existing origination workflows.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$2B lender using Loan Intelligence", "why_now": "Recent source-backed funding and public product evidence make mortgage, ai agents, fintech worth tracking."}, "risks": [{"claim": "The risk is enterprise pilots turning into custom services.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$2B lender using Loan Intelligence', 'Fintech', 'Seed', '$6M', NULL, NULL, NULL, 'US', 'mortgage,ai agents,fintech,loan origination', 'Kleiner Perkins', '{"twitter": "https://x.com/BalerionAI", "linkedin": "https://www.linkedin.com/company/balerion-ai/"}', 0, 'balerion.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-basata', 'basata', 'www.basata.ai', 'https://www.basata.ai', 'Basata', 'AI referral intake and call handling for specialty practices.', 'Healthcare AI usually chases clinicians; this aims at the fax pile between referral and visit. Basata processes faxes, creates EHR charts, calls patients with voice agents, and claims 500,000 referrals processed with 100,000 in the last month. Unlike ambient scribes, the bet is owning the handoff before care starts. The risk is how much specialty-specific workflow knowledge has to be rebuilt practice by practice.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.basata.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/07/the-back-office-problem-that-explains-why-specialists-never-call-you-back/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Basata: AI referral intake and call handling for specialty practices.", "source_ids": ["official_site"]}, {"claim": "Basata processes faxes, creates EHR charts, calls patients with voice agents, and claims 500,000 referrals processed with 100,000 in the last month.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "$21M Series A for referral ops", "why_now": "Recent source-backed funding and public product evidence make healthcare ai, referrals, voice agents worth tracking."}, "risks": [{"claim": "The risk is how much specialty-specific workflow knowledge has to be rebuilt practice by practice.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$21M Series A for referral ops', 'HealthTech', 'Series A', '$21M', NULL, NULL, NULL, 'US', 'healthcare ai,referrals,voice agents,practice operations', 'Basis Set Ventures, Cowboy Ventures, Sofeon', NULL, 1, 'basata.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-branchlab', 'branchlab', 'branchlab.com', 'https://branchlab.com/pathwai', 'BranchLab', 'AI audience platform for pharma commercialization.', 'The sharper idea is removing PHI from pharma targeting instead of pretending healthcare marketing is ordinary ads. Pathwai learns from de-identified health signals, clusters patient journeys, and cites outcomes like 2,000 extra patients reached in three weeks and 90% lower cost per patient. Compared with static audience files, it sells a learning system for commercial teams. The risk is whether better targeting feels like better healthcare to anyone outside pharma.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://branchlab.com/pathwai", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/branchlab-raises-26m-series-a-led-by-mckesson-ventures-to-bring-ai-to-pharma-commercialization-302770272.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes BranchLab: AI audience platform for pharma commercialization.", "source_ids": ["official_site"]}, {"claim": "Pathwai learns from de-identified health signals, clusters patient journeys, and cites outcomes like 2,000 extra patients reached in three weeks and 90% lower cost per patient.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "2,000 patients in 3 weeks", "why_now": "Recent source-backed funding and public product evidence make pharma, healthcare ai, audience targeting worth tracking."}, "risks": [{"claim": "The risk is whether better targeting feels like better healthcare to anyone outside pharma.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '2,000 patients in 3 weeks', 'HealthTech', 'Series A', '$26M', NULL, NULL, NULL, 'US', 'pharma,healthcare ai,audience targeting,commercialization', 'McKesson Ventures', NULL, 1, 'branchlab.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cal-com', 'cal-com', 'cal.com', 'https://cal.com', 'Cal.com', 'Open source scheduling infrastructure.', 'The interesting move was not cloning Calendly in public. It was treating scheduling as infrastructure: a self-hosted option, API hooks, and a hosted product for teams that do not want to run it themselves. That is a sharper bet than generic booking software. Cal.com is selling control, not just calendar pages.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://cal.com", "type": "official"}, {"id": "funding_1", "label": "Cal.com", "url": "https://cal.com/blog", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Cal.com: Open source scheduling infrastructure.", "source_ids": ["official_site"]}, {"claim": "It was treating scheduling as infrastructure: a self-hosted option, API hooks, and a hosted product for teams that do not want to run it themselves.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Open source done right", "why_now": "Recent source-backed funding and public product evidence make scheduling, open source, calendar worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Open source done right', 'SaaS', 'Series A', '$25M', 2021, '30-50', 'San Francisco', 'US', 'scheduling,open source,calendar,productivity', 'Dick Costolo, Joseph Jacks (OSS Capital), Peer Richelsen', '{"github": "https://github.com/calcom/cal.com", "twitter": "https://x.com/calabordar", "linkedin": "https://linkedin.com/company/cal-com"}', 0, 'cal-com.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-certo', 'certo', 'www.askcerto.com', 'https://www.askcerto.com/', 'Certo', 'AI compliance agents for ingredient, formula, label, and market-entry checks.', 'The useful idea is turning compliance into product-specific checks instead of another spreadsheet of regulations. Certo shows ingredient extraction, CAS mapping, formula checks, SDS/PIF/CPSR generation, market readiness, audit trails, and daily regulatory feeds across 70+ countries. Unlike generic legal copilots, it narrows the agent to consumer-product labels and supplier documents.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.askcerto.com/", "type": "official"}, {"id": "funding_1", "label": "Tech Funding News", "url": "https://techfundingnews.com/certo-4m-seed-ai-compliance-cpg/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Certo: AI compliance agents for ingredient, formula, label, and market-entry checks.", "source_ids": ["official_site"]}, {"claim": "Certo shows ingredient extraction, CAS mapping, formula checks, SDS/PIF/CPSR generation, market readiness, audit trails, and daily regulatory feeds across 70+ countries.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Consumer compliance agents", "why_now": "Recent source-backed funding and public product evidence make compliance, consumer goods, regulatory worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Consumer compliance agents', 'SaaS', 'Seed', '$4M', NULL, NULL, NULL, 'Europe', 'compliance,consumer goods,regulatory,ai agents,workflow', 'daphni', NULL, 1, 'certo.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ciridae', 'ciridae', 'www.ciridae.com', 'https://www.ciridae.com', 'Ciridae', 'AI operating systems for real-economy businesses.', 'The sharper bet is that mid-market operators need rebuilt workflows, not another AI sidebar. Ciridae shows AP invoices, CRM, reporting, project management, and Knight case metrics like $5M revenue uplift and 100% of A/P invoices processed. Unlike horizontal copilots, it embeds into how restoration or logistics companies already run. The risk is whether services work scales without becoming consulting.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.ciridae.com", "type": "official"}, {"id": "funding_1", "label": "Fortune", "url": "https://fortune.com/2026/05/11/a16z-apple-alums-20m-ai-real-businesses/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Ciridae: AI operating systems for real-economy businesses.", "source_ids": ["official_site"]}, {"claim": "Ciridae shows AP invoices, CRM, reporting, project management, and Knight case metrics like $5M revenue uplift and 100% of A/P invoices processed.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "100% AP invoices processed", "why_now": "Recent source-backed funding and public product evidence make ai operations, industrial services, private equity worth tracking."}, "risks": [{"claim": "The risk is whether services work scales without becoming consulting.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '100% AP invoices processed', 'AI / ML', 'Seed', '$20M', NULL, NULL, NULL, 'US', 'ai operations,industrial services,private equity,workflow automation', 'Accel, Andreessen Horowitz, General Catalyst', NULL, 1, 'ciridae.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-config', 'config', 'config.inc', 'https://config.inc/product', 'Config', 'Robot training-data platform for robotics foundation models.', 'The strongest bet is that robot data should be fabricated like semiconductors, not collected one lab at a time. Config''s platform walks from gripper design to data strategy, acquisition, labeling, action estimation, model training, and evaluation; CFG-1 claims 100K in-house human-data hours, 2B parameters, and sub-50ms RTX 5090 latency. Compared with robot builders chasing hardware, this sells the data foundry. The risk is that customers still need proof on their own factory tasks.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://config.inc/product", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/11/koreas-biggest-manufacturers-back-config-the-tsmc-of-robot-data/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Config: Robot training-data platform for robotics foundation models.", "source_ids": ["official_site"]}, {"claim": "Config''s platform walks from gripper design to data strategy, acquisition, labeling, action estimation, model training, and evaluation; CFG-1 claims 100K in-house human-data hours, 2B parameters, and sub-50ms RTX 5090 latency.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "100K hours of robot data", "why_now": "Recent source-backed funding and public product evidence make robotics, training data, foundation models worth tracking."}, "risks": [{"claim": "The risk is that customers still need proof on their own factory tasks.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '100K hours of robot data', 'AI / ML', 'Seed', '$27M', NULL, NULL, NULL, 'China / Asia', 'robotics,training data,foundation models,physical ai', 'Samsung Venture Investment', NULL, 0, 'config.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-copilotkit', 'copilotkit', 'www.copilotkit.ai', 'https://www.copilotkit.ai', 'CopilotKit', 'Open-source framework for app-native AI agents and generative UI.', 'Most agent products still end at a chat box; the sharper bet is giving agents a front end. CopilotKit exposes React and Angular SDKs, AG-UI, MCP Apps, threads, GitHub-backed docs, and a one-command npx path. Unlike Vercel''s AI SDK or ChatGPT Apps, it is trying to be the neutral UI layer enterprises can self-host. The risk is that protocol gravity is hard to keep once platform vendors bundle the same primitives.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.copilotkit.ai", "type": "official"}, {"id": "funding_1", "label": "CopilotKit", "url": "https://www.copilotkit.ai/blog/series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes CopilotKit: Open-source framework for app-native AI agents and generative UI.", "source_ids": ["official_site"]}, {"claim": "CopilotKit exposes React and Angular SDKs, AG-UI, MCP Apps, threads, GitHub-backed docs, and a one-command npx path.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "AG-UI for app-native agents", "why_now": "Recent source-backed funding and public product evidence make ai agents, generative ui, developer tools worth tracking."}, "risks": [{"claim": "The risk is that protocol gravity is hard to keep once platform vendors bundle the same primitives.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'AG-UI for app-native agents', 'DevTools', 'Series A', '$27M', NULL, NULL, NULL, 'US', 'ai agents,generative ui,developer tools,open source', 'Glilot Capital, NFX, SignalFire', '{"github": "https://github.com/CopilotKit/CopilotKit", "twitter": "https://x.com/CopilotKit", "linkedin": "https://www.linkedin.com/company/copilotkit/"}', 1, 'copilotkit.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-corgi', 'corgi', 'www.corgi.insure', 'https://www.corgi.insure', 'Corgi', 'Instant startup insurance quotes and modular coverage.', 'Startup insurance usually feels like paperwork wearing a broker''s suit; this is closer to checkout. Corgi exposes instant quotes, 4 stage-based coverage paths, D&O, Cyber, Tech E&O, and customer proof from Deel, Bland, Intryc, and other startups. Unlike Vouch or Embroker, the bet is that founders want insurance to feel as fast as buying compute. The risk is that underwriting speed has to survive messier companies than YC-style software teams.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.corgi.insure", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/06/insurance-startup-corgi-hits-1-3b-valuation-4-months-after-its-series-a/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Corgi: Instant startup insurance quotes and modular coverage.", "source_ids": ["official_site"]}, {"claim": "Corgi exposes instant quotes, 4 stage-based coverage paths, D&O, Cyber, Tech E&O, and customer proof from Deel, Bland, Intryc, and other startups.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$160M Series B for instant insurance", "why_now": "Recent source-backed funding and public product evidence make insurance, fintech, startups worth tracking."}, "risks": [{"claim": "The risk is that underwriting speed has to survive messier companies than YC-style software teams.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$160M Series B for instant insurance', 'Fintech', 'Series B', '$160M', NULL, NULL, NULL, 'US', 'insurance,fintech,startups,founder tools', 'TCV, Kindred Ventures, Leblon Capital, First Order Fund', '{"twitter": "https://x.com/UseCorgi", "linkedin": "https://www.linkedin.com/company/corgi-insurance"}', 1, 'corgi.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-crew-carbon', 'crew-carbon', 'crewcarbon.com', 'https://crewcarbon.com', 'CREW Carbon', 'Wastewater process optimization that also delivers measured carbon removal.', 'This is climate tech with an operator''s wedge: make sewage plants cheaper before selling carbon removal. CREW uses calcium carbonate dosing, closed-system measurement, and projects at nearly 10 facilities; one utility may defer a $350M upgrade. Unlike credits-first carbon removal, the buyer also gets better pH, settleability, and chemical spend. That dual value is why it feels less fragile than most climate markets.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://crewcarbon.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/crew-raises-25m-of-funding-to-scale-wastewater-treatment-optimization-technology-as-climate-solution-302772585.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes CREW Carbon: Wastewater process optimization that also delivers measured carbon removal.", "source_ids": ["official_site"]}, {"claim": "CREW uses calcium carbonate dosing, closed-system measurement, and projects at nearly 10 facilities; one utility may defer a $350M upgrade.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Climate, infrastructure, or operations teams evaluating measurable sustainability workflows.", "category": "Climate / Sustainability", "differentiation": "$350M plant upgrade deferred", "why_now": "Recent source-backed funding and public product evidence make water tech, carbon removal, wastewater worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$350M plant upgrade deferred', 'Climate / Sustainability', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'water tech,carbon removal,wastewater,climate', 'Burnt Island Ventures', NULL, 1, 'crew-carbon.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cursor', 'cursor', 'cursor.com', 'https://cursor.com', 'Cursor', 'The AI-first code editor.', 'The right bet was not copilot-inside-VSCode, but an editor rebuilt around the model. Tab completion, inline diffs, and cmd-K feel native rather than bolted on. By forking VS Code instead of starting from scratch, Cursor kept the muscle memory and changed the center of gravity. That is why it feels sticky instead of merely novel.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://cursor.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2024/08/09/anysphere-a-github-copilot-rival-has-raised-60m-series-a-at-400m-valuation-from-a16z-thrive-sources-say/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Cursor: The AI-first code editor.", "source_ids": ["official_site"]}, {"claim": "Tab completion, inline diffs, and cmd-K feel native rather than bolted on.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Changed how developers write code", "why_now": "Recent source-backed funding and public product evidence make ai, code editor, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Changed how developers write code', 'AI / ML', 'Series A', '$60M', 2022, '50-100', 'San Francisco', 'US', 'ai,code editor,developer tools,productivity', 'Andreessen Horowitz, Thrive Capital, OpenAI Startup Fund', '{"github": "https://github.com/getcursor", "twitter": "https://x.com/cursor_ai", "linkedin": "https://linkedin.com/company/cursor-ai"}', 1, 'cursor.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cvrd-health', 'cvrd-health', 'www.becvrd.com', 'https://www.becvrd.com', 'CVRD Health', 'Fringe benefit optimization and ICHRA compliance platform for government contractors.', 'Someone finally treated fringe benefits for federal contractors as an operating system, not a broker spreadsheet. CVRD models SCA/DBRA obligations, tracks H&W dollars in real time, manages ICHRAs, and shows an Aptive case with $536,870 annual savings across 151 enrolled employees. Unlike generic benefits software, the bet is owning the narrow compliance math where margins leak. The risk is whether service-heavy advocacy scales beyond early GovCon accounts.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.becvrd.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/cvrd-health-announces-5m-seed-round-led-by-upfront-ventures-to-modernize-benefits-compliance-for-federal-government-contractors-302779218.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes CVRD Health: Fringe benefit optimization and ICHRA compliance platform for government contractors.", "source_ids": ["official_site"]}, {"claim": "CVRD models SCA/DBRA obligations, tracks H&W dollars in real time, manages ICHRAs, and shows an Aptive case with $536,870 annual savings across 151 enrolled employees.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "151-enrollee GovCon case study", "why_now": "Recent source-backed funding and public product evidence make benefits, govcon, compliance worth tracking."}, "risks": [{"claim": "The risk is whether service-heavy advocacy scales beyond early GovCon accounts.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '151-enrollee GovCon case study', 'SaaS', 'Seed', '$5M', NULL, NULL, NULL, 'US', 'benefits,govcon,compliance,healthcare,hr tech', 'Upfront Ventures', '{"linkedin": "https://www.linkedin.com/company/cvrdhealth/"}', 1, 'cvrd-health.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-dust', 'dust', 'dust.tt', 'https://dust.tt', 'Dust', 'Multiplayer AI workspace where teams build and run shared workplace agents.', 'The useful bet is making enterprise AI collaborative instead of a private chat window. Dust gives teams shared agents, Slack/GitHub/Drive connectors, model choice, RBAC, audit logs, and a semantic layer that improves from use. Unlike one-off copilots, the workspace makes agent behavior visible to teammates. The risk is whether agent sprawl becomes the new collaboration tax.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://dust.tt", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/18/3296726/0/en/Dust-raises-40M-to-make-AI-multiplayer-inside-the-enterprise.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Dust: Multiplayer AI workspace where teams build and run shared workplace agents.", "source_ids": ["official_site"]}, {"claim": "Dust gives teams shared agents, Slack/GitHub/Drive connectors, model choice, RBAC, audit logs, and a semantic layer that improves from use.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Shared agents for teams", "why_now": "Recent source-backed funding and public product evidence make ai agents, enterprise ai, collaboration worth tracking."}, "risks": [{"claim": "The risk is whether agent sprawl becomes the new collaboration tax.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Shared agents for teams', 'AI / ML', 'Series B', '$40M', NULL, NULL, NULL, 'Global / Remote', 'ai agents,enterprise ai,collaboration,knowledge management', 'Sequoia Capital', NULL, 1, 'dust.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-eleven-labs', 'eleven-labs', 'elevenlabs.io', 'https://elevenlabs.io', 'ElevenLabs', 'AI voice generation and speech synthesis platform.', 'The surprising thing is not that voice cloning works. It is that 30 seconds of audio can already get you something commercially usable. ElevenLabs is betting this becomes infrastructure for dubbing, audiobooks, and accessibility, not just a viral demo. That is a narrower and more durable business than AI voice as spectacle.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://elevenlabs.io", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2024/01/22/voice-cloning-startup-elevenlabs-lands-80m-achieves-unicorn-status/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes ElevenLabs: AI voice generation and speech synthesis platform.", "source_ids": ["official_site"]}, {"claim": "It is that 30 seconds of audio can already get you something commercially usable.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Voice AI that actually sounds human", "why_now": "Recent source-backed funding and public product evidence make voice ai, speech synthesis, text to speech worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Voice AI that actually sounds human', 'AI / ML', 'Series B', '$80M', 2022, '50-100', 'New York', 'US', 'voice ai,speech synthesis,text to speech,artificial intelligence', 'Andreessen Horowitz, Nat Friedman, Daniel Gross', '{"github": "https://github.com/elevenlabs", "twitter": "https://x.com/elevenlabsio", "linkedin": "https://linkedin.com/company/elevenlabs"}', 0, 'eleven-labs.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-enzo-health', 'enzo-health', 'www.enzo.health', 'https://www.enzo.health', 'Enzo Health', 'Home health intake, scribe, and QA workflows with AI.', 'Home health software often treats the nurse as the data-entry layer; this pushes the paperwork into the visit itself. Enzo shows Intake, Scribe, and QA modules with OASIS validation, referral checks, secure messaging, and 5-minute intake-to-admission claims. Unlike generic medical scribes, the bet is one thread from bedside note to reimbursement. The risk is integrating deeply enough with fragmented agency systems.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.enzo.health", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/enzo-health-raises-26m-to-deploy-ai-across-home-health-to-meet-unprecedented-nationwide-demand-for-post-acute-care-302760538.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Enzo Health: Home health intake, scribe, and QA workflows with AI.", "source_ids": ["official_site"]}, {"claim": "Enzo shows Intake, Scribe, and QA modules with OASIS validation, referral checks, secure messaging, and 5-minute intake-to-admission claims.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "$20M Series A for home health AI", "why_now": "Recent source-backed funding and public product evidence make home health, clinical documentation, intake worth tracking."}, "risks": [{"claim": "The risk is integrating deeply enough with fragmented agency systems.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$20M Series A for home health AI', 'HealthTech', 'Series A', '$20M', NULL, NULL, NULL, 'US', 'home health,clinical documentation,intake,quality assurance', 'N47, Gradient, Tandem Ventures, Rigby Watts', NULL, 1, 'enzo-health.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-equipifi', 'equipifi', 'www.equipifi.com', 'https://www.equipifi.com', 'equipifi', 'White-label BNPL and installment-lending platform for banks and credit unions.', 'The better BNPL bet is hiding inside the bank app, not at checkout. equipifi gives credit unions and banks pre-approved pay-over-time offers, debit-card installment loans, eligibility controls, reporting, and launch paths that need about 10 team hours. Unlike consumer BNPL brands, it sells the rails to institutions that already hold the relationship. The product is more useful than beautiful, which keeps the rating grounded.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.equipifi.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/equipifi-secures-34-million-series-b-to-accelerate-buy-now-pay-later-across-us-financial-institutions-302771649.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes equipifi: White-label BNPL and installment-lending platform for banks and credit unions.", "source_ids": ["official_site"]}, {"claim": "equipifi gives credit unions and banks pre-approved pay-over-time offers, debit-card installment loans, eligibility controls, reporting, and launch paths that need about 10 team hours.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "Bank-native BNPL rails", "why_now": "Recent source-backed funding and public product evidence make fintech, bnpl, credit unions worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 3, 'Bank-native BNPL rails', 'Fintech', 'Series B', '$34M', NULL, NULL, NULL, 'US', 'fintech,bnpl,credit unions,banking', 'Left Lane Capital', NULL, 0, 'equipifi.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ethos', 'ethos', 'agent.askethos.com', 'https://agent.askethos.com', 'Ethos', 'AI-matched expert network with voice-based onboarding.', 'The sharper idea is that expert networks should know what people can do, not just what titles they held. Ethos uses voice onboarding, public-source enrichment, paid opportunity cards, and 35,000 weekly expert joins to build a deeper matching layer. Unlike LinkedIn search or GLG-style forms, the bet is that interviews create a better skill graph than resumes. The risk is quality control once the network scales faster than its eight-person team.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://agent.askethos.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/06/ethos-raises-22-75m-from-a16z-for-its-expert-network-with-voice-onboarding/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Ethos: AI-matched expert network with voice-based onboarding.", "source_ids": ["official_site"]}, {"claim": "Ethos uses voice onboarding, public-source enrichment, paid opportunity cards, and 35,000 weekly expert joins to build a deeper matching layer.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Supply-and-demand operators evaluating marketplace coordination workflows.", "category": "Marketplace", "differentiation": "35K experts joining each week", "why_now": "Recent source-backed funding and public product evidence make expert network, ai matching, voice onboarding worth tracking."}, "risks": [{"claim": "The risk is quality control once the network scales faster than its eight-person team.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '35K experts joining each week', 'Marketplace', 'Series A', '$22.75M', NULL, NULL, NULL, 'Europe', 'expert network,ai matching,voice onboarding,marketplace', 'Andreessen Horowitz, General Catalyst, XTX Markets, Evantic Capital, Common Magic', NULL, 1, 'ethos.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-fazeshift', 'fazeshift', 'www.fazeshift.com', 'https://www.fazeshift.com', 'Fazeshift', 'AI accounts receivable agents for finance teams.', 'The bet is boring on purpose: automate the cash cycle inside the systems finance teams already trust, not replace them. Fazeshift shows cash application, collections, contract review, Stripe/NetSuite/Sage Intacct billing, SOC 1/2, and customer claims like 50% DSO reduction. Unlike generic finance copilots, each agent maps to a stubborn AR job. The test is whether invoice edge cases stay tractable at scale.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.fazeshift.com", "type": "official"}, {"id": "funding_1", "label": "Fazeshift", "url": "https://www.fazeshift.com/newsroom", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Fazeshift: AI accounts receivable agents for finance teams.", "source_ids": ["official_site"]}, {"claim": "Fazeshift shows cash application, collections, contract review, Stripe/NetSuite/Sage Intacct billing, SOC 1/2, and customer claims like 50% DSO reduction.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$22M Series A for AR agents", "why_now": "Recent source-backed funding and public product evidence make accounts receivable, finance ops, ai agents worth tracking."}, "risks": [{"claim": "The test is whether invoice edge cases stay tractable at scale.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$22M Series A for AR agents', 'Fintech', 'Series A', '$22M', NULL, NULL, NULL, 'US', 'accounts receivable,finance ops,ai agents,billing automation', 'F-Prime Capital', NULL, 1, 'fazeshift.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-featherless', 'featherless', 'featherless.ai', 'https://featherless.ai', 'Featherless', 'Serverless API access to 30,000+ open-weight AI models.', 'The bet is open-model inference without renting a GPU box or accepting a closed API. Featherless exposes 30,000+ models through one API, docs for chat completions, embeddings, tool calling, vision, and a live model library with usage counts. Unlike raw GPU clouds, it sells model choice and predictable pricing as the product. The hard part is keeping that promise when every niche model wants different hardware.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://featherless.ai", "type": "official"}, {"id": "funding_1", "label": "Featherless", "url": "https://featherless.ai/blog/series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Featherless: Serverless API access to 30,000+ open-weight AI models.", "source_ids": ["official_site"]}, {"claim": "Featherless exposes 30,000+ models through one API, docs for chat completions, embeddings, tool calling, vision, and a live model library with usage counts.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "$20M Series A for 30K models", "why_now": "Recent source-backed funding and public product evidence make ai infrastructure, inference, open models worth tracking."}, "risks": [{"claim": "The hard part is keeping that promise when every niche model wants different hardware.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$20M Series A for 30K models', 'DevTools', 'Series A', '$20M', NULL, NULL, NULL, 'Global / Remote', 'ai infrastructure,inference,open models,developer tools', 'AMD Ventures', NULL, 1, 'featherless.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-flexprice', 'flexprice', 'flexprice.io', 'https://flexprice.io/', 'Flexprice', 'Open-source usage billing infrastructure for AI and API-first companies.', 'The bet is that AI pricing breaks before product-market fit does. Flexprice exposes metering, credits, hybrid plans, SDKs, MCP support, a CLI, GitHub repo, and case-study proof around 20B events/month. Unlike seat-based billing tools, it treats event streams and pricing experiments as the product surface. The risk is whether finance teams trust open-source billing when revenue recognition gets messy.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://flexprice.io/", "type": "official"}, {"id": "funding_1", "label": "ET Entrepreneur", "url": "https://entrepreneur.economictimes.indiatimes.com/news/funding/flexprice-secures-15-million-in-seed-funding-to-revolutionize-ai-billing-solutions/131320984", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Flexprice: Open-source usage billing infrastructure for AI and API-first companies.", "source_ids": ["official_site"]}, {"claim": "Flexprice exposes metering, credits, hybrid plans, SDKs, MCP support, a CLI, GitHub repo, and case-study proof around 20B events/month.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "AI usage billing stack", "why_now": "Recent source-backed funding and public product evidence make billing, usage metering, pricing worth tracking."}, "risks": [{"claim": "The risk is whether finance teams trust open-source billing when revenue recognition gets messy.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'AI usage billing stack', 'DevTools', 'Seed', '$1.5M', NULL, NULL, NULL, 'Global / Remote', 'billing,usage metering,pricing,developer tools,ai infrastructure', 'Shastra VC', '{"github": "https://github.com/flexprice/flexprice"}', 1, 'flexprice.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-gizmo', 'gizmo', 'gizmo.ai', 'https://gizmo.ai', 'Gizmo', 'AI study app that turns notes into flashcards, quizzes, and streak-based learning loops.', 'Most study apps still behave like digital stationery; the sharper move is designing for the attention span TikTok trained instead. Gizmo pairs AI-generated flashcards with streaks, leaderboards, limited lives, and social challenges; it reaches 13 million users in 120 countries. Instead of asking students to become more disciplined, it is betting that better habits can piggyback on addictive product design. The risk is that engagement mechanics outrun learning depth once the novelty wears off.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://gizmo.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/15/ai-learning-app-gizmo-levels-up-with-13m-users-and-a-22m-investment/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Gizmo: AI study app that turns notes into flashcards, quizzes, and streak-based learning loops.", "source_ids": ["official_site"]}, {"claim": "Gizmo pairs AI-generated flashcards with streaks, leaderboards, limited lives, and social challenges; it reaches 13 million users in 120 countries.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Learners, educators, or training teams evaluating learning and study workflows.", "category": "EdTech", "differentiation": "TikTok loops for studying", "why_now": "Recent source-backed funding and public product evidence make education, study tools, flashcards worth tracking."}, "risks": [{"claim": "The risk is that engagement mechanics outrun learning depth once the novelty wears off.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'TikTok loops for studying', 'EdTech', 'Series A', '$22M', NULL, NULL, NULL, 'Europe', 'education,study tools,flashcards,consumer app', 'Shine Capital, Ada Ventures, Seek Investments, GSV, NFX', NULL, 1, 'gizmo.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-govwell', 'govwell', 'www.govwell.com', 'https://www.govwell.com', 'GovWell', 'AI permitting and licensing platform for local governments.', 'This is civic software with a painfully concrete wedge: permits, inspections, licenses, and code enforcement instead of vague government change. GovWell shows AI AutoCheck, 5,000+ processes, 100+ agencies, 35+ states, and processing that can move from 10 days to under an hour. Unlike legacy municipal systems, the product sells speed without making staff change departments. Procurement pace is the obvious drag.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.govwell.com", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/govwell-raises-25m-series-a-led-by-insight-partners-to-build-the-ai-operating-system-for-modern-government-302770627.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes GovWell: AI permitting and licensing platform for local governments.", "source_ids": ["official_site"]}, {"claim": "GovWell shows AI AutoCheck, 5,000+ processes, 100+ agencies, 35+ states, and processing that can move from 10 days to under an hour.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "100+ agencies, $25M Series A", "why_now": "Recent source-backed funding and public product evidence make civic software, permitting, licensing worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '100+ agencies, $25M Series A', 'SaaS', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'civic software,permitting,licensing,local government', 'Insight Partners', NULL, 1, 'govwell.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-grai', 'grai', 'www.grai.fm', 'https://www.grai.fm', 'GRAI', 'Social AI music app for remixing songs with friends while keeping artist control in the loop.', 'Most AI music tools treat listeners like failed producers; the better consumer bet is participation without pretending everyone wants a DAW. GRAI is live as an iPhone app and raised a $9M seed round, letting people react to friends'' tracks and flip songs into new moods. Unlike Suno or Udio, it starts from existing music and artist opt-in rather than blank-page generation. The hard part is whether labels give enough catalog access for the social loop to matter.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.grai.fm", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/21/grai-believes-ai-can-make-music-more-social-not-replace-artists/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes GRAI: Social AI music app for remixing songs with friends while keeping artist control in the loop.", "source_ids": ["official_site"]}, {"claim": "GRAI is live as an iPhone app and raised a $9M seed round, letting people react to friends'' tracks and flip songs into new moods.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Creative teams and individual creators evaluating production workflows.", "category": "Creator Tools", "differentiation": "Social remix, not song gen", "why_now": "Recent source-backed funding and public product evidence make music, ai, remix worth tracking."}, "risks": [{"claim": "The hard part is whether labels give enough catalog access for the social loop to matter.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Social remix, not song gen', 'Creator Tools', 'Seed', '$9M', NULL, NULL, NULL, 'Europe', 'music,ai,remix,social apps,creator tools', 'Khosla Ventures, Inovo VC', '{"linkedin": "https://www.linkedin.com/company/grai-fm/"}', 1, 'grai.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-granola', 'granola', 'www.granola.ai', 'https://www.granola.ai', 'Granola', 'AI meeting notes that turn transcripts into searchable team context.', 'Meeting notes only looked saturated until someone removed the bot and treated meetings as company memory instead. Granola''s local transcription, MCP server, and new personal plus enterprise APIs make it feel closer to context infrastructure than another transcript widget. Where most note-takers sell recall, this is betting that shared context matters more than summaries. The risk is that the product loses elegance as it stretches from a sharp Mac app into enterprise workflow plumbing.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.granola.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/03/25/granola-raises-125m-hits-1-5b-valuation-as-it-expands-from-meeting-notetaker-to-enterprise-ai-app/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Granola: AI meeting notes that turn transcripts into searchable team context.", "source_ids": ["official_site"]}, {"claim": "Meeting notes only looked saturated until someone removed the bot and treated meetings as company memory instead.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Bot-free meeting context layer", "why_now": "Recent source-backed funding and public product evidence make meeting notes, productivity, knowledge management worth tracking."}, "risks": [{"claim": "The risk is that the product loses elegance as it stretches from a sharp Mac app into enterprise workflow plumbing.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Bot-free meeting context layer', 'SaaS', 'Series C', '$125M', NULL, NULL, NULL, 'Europe', 'meeting notes,productivity,knowledge management,ai assistant', 'Index Ventures, Kleiner Perkins, Lightspeed Venture Partners, Spark Capital, NFDG', '{"twitter": "https://x.com/meetgranola", "linkedin": "https://www.linkedin.com/company/meetgranola"}', 1, 'granola.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-hellbender', 'hellbender', 'hellbender.com', 'https://hellbender.com/hellbender-products/', 'Hellbender', 'Edge AI camera systems and carrier boards for robotics and physical AI teams.', 'The useful bet is putting more physical AI on the camera instead of in a remote demo stack. Hellbender sells stereo AI cameras, 64-camera Vine systems, carrier boards, and CVaaS for teams that would rather test robots than wire processors. Unlike many defense-adjacent AI pitches, the product catalog is visible and shippable. Manufacturing discipline may matter more here than model cleverness.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://hellbender.com/hellbender-products/", "type": "official"}, {"id": "funding_1", "label": "Hellbender", "url": "https://hellbender.com/hellbender-secures-12-5m-seed-round-to-accelerate-domestic-manufacturing-of-physical-ai-and-launch-its-on-edge-camera-line/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Hellbender: Edge AI camera systems and carrier boards for robotics and physical AI teams.", "source_ids": ["official_site"]}, {"claim": "Hellbender sells stereo AI cameras, 64-camera Vine systems, carrier boards, and CVaaS for teams that would rather test robots than wire processors.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Stereo cameras for edge AI", "why_now": "Recent source-backed funding and public product evidence make edge ai, robotics, computer vision worth tracking."}, "risks": [{"claim": "Manufacturing discipline may matter more here than model cleverness.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Stereo cameras for edge AI', 'AI / ML', 'Seed', '$12.5M', NULL, NULL, NULL, 'US', 'edge ai,robotics,computer vision,hardware', 'Magarac Venture Partners, Veredas Partners', NULL, 1, 'hellbender.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-hilbert', 'hilbert', 'hilberts.ai', 'https://hilberts.ai', 'Hilbert', 'AI growth infrastructure for B2C revenue decisions.', 'Growth analytics usually stops at dashboards; this is trying to become the decision layer after the chart. Hilbert shows anomaly detection, root-cause analysis, counterfactuals, pLTV targeting, and agent-driven growth tasks in one product surface. Unlike BI tools or in-house ML projects, the bet is that B2C teams want actions tied to cohorts and unit economics, not another report. The risk is proving those actions move revenue outside the demo data.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://hilberts.ai", "type": "official"}, {"id": "funding_1", "label": "Gunderson Dettmer", "url": "https://www.gunder.com/en/news-insights/client-news/hilbert-announces-28-million-usd-series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Hilbert: AI growth infrastructure for B2C revenue decisions.", "source_ids": ["official_site"]}, {"claim": "Hilbert shows anomaly detection, root-cause analysis, counterfactuals, pLTV targeting, and agent-driven growth tasks in one product surface.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$28M Series A for growth infra", "why_now": "Recent source-backed funding and public product evidence make growth analytics, b2c ai, decision intelligence worth tracking."}, "risks": [{"claim": "The risk is proving those actions move revenue outside the demo data.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$28M Series A for growth infra', 'AI / ML', 'Series A', '$28M', NULL, NULL, NULL, 'US', 'growth analytics,b2c ai,decision intelligence,marketing', 'Andreessen Horowitz', NULL, 1, 'hilbert.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-juliahub', 'juliahub', 'juliahub.com', 'https://juliahub.com', 'JuliaHub', 'Agentic simulation and digital-twin tooling for hardware engineering teams.', 'Someone finally treated engineering simulation like a software workflow, not a CAD afterthought. Dyad 3.0 turns Julia models, SciML, case studies, and cloud runs into an AI-native workspace for physical systems, with public proof from ASML, Boeing, NASA, and Williams Racing. The bet is that hardware teams want agents constrained by equations rather than chatbots guessing at parts. The risk is whether that craft reaches engineers outside the Julia faithful.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://juliahub.com", "type": "official"}, {"id": "funding_1", "label": "JuliaHub", "url": "https://juliahub.com/blog/juliahub-raises-65m-series-b-launches-dyad-3.0", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes JuliaHub: Agentic simulation and digital-twin tooling for hardware engineering teams.", "source_ids": ["official_site"]}, {"claim": "Someone finally treated engineering simulation like a software workflow, not a CAD afterthought.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$65M Series B for Dyad 3.0", "why_now": "Recent source-backed funding and public product evidence make scientific ai, simulation, digital twins worth tracking."}, "risks": [{"claim": "The risk is whether that craft reaches engineers outside the Julia faithful.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$65M Series B for Dyad 3.0', 'AI / ML', 'Series B', '$65M', NULL, NULL, NULL, 'US', 'scientific ai,simulation,digital twins,hardware engineering', 'Dorilton Ventures', NULL, 1, 'juliahub.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-kin-health', 'kin-health', 'www.meetkin.com', 'https://www.meetkin.com', 'Kin Health', 'Patient app that records doctor visits and turns them into clear next steps.', 'The bet is that the missing layer in care is memory, not another portal. Kin records doctor visits, extracts next steps, and lets a patient share the summary with family before the next appointment. Unlike clinician scribes, it starts with the person who forgets 80% of instructions by the parking lot. Free patient distribution is elegant; consent norms in exam rooms are the hard part.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.meetkin.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/18/kin-health-raises-9m-to-build-an-ai-notetaker-for-patients/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Kin Health: Patient app that records doctor visits and turns them into clear next steps.", "source_ids": ["official_site"]}, {"claim": "VentureDex product review notes that unlike clinician scribes, it starts with the person who forgets 80% of instructions by the parking lot.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "Patient-owned visit memory", "why_now": "Recent source-backed funding and public product evidence make healthtech, patient notes, care coordination worth tracking."}, "risks": [{"claim": "Free patient distribution is elegant; consent norms in exam rooms are the hard part.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Patient-owned visit memory', 'HealthTech', 'Seed', '$9M', NULL, NULL, NULL, 'US', 'healthtech,patient notes,care coordination,ai scribe', 'Maveron', NULL, 1, 'kin-health.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-krea', 'krea', 'www.krea.ai', 'https://www.krea.ai', 'Krea', 'AI creative suite for generating, editing, and controlling images, video, and 3D assets.', 'Creative AI gets interesting when it treats models as material instead of magic boxes. Krea puts Krea 1, video, enhancer, realtime, editing, LoRA training, and style transfer into one workspace; the app exposes prompt, model, ratio, and resolution controls before it asks for a sales call. Unlike prompt-only wrappers, the bet is that visual creators want handles they can keep adjusting. The risk is that bundling every medium can blur the point if the controls stop feeling precise.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.krea.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2025/04/07/kreas-founders-snubbed-postgrad-grants-from-the-king-of-spain-to-build-their-ai-startup-now-its-valued-at-500m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Krea: AI creative suite for generating, editing, and controlling images, video, and 3D assets.", "source_ids": ["official_site"]}, {"claim": "Krea puts Krea 1, video, enhancer, realtime, editing, LoRA training, and style transfer into one workspace; the app exposes prompt, model, ratio, and resolution controls before it asks for a sales call.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Creative teams and individual creators evaluating production workflows.", "category": "Creator Tools", "differentiation": "Krea 1 plus visual control handles", "why_now": "Recent source-backed funding and public product evidence make ai creative tools, image generation, video generation worth tracking."}, "risks": [{"claim": "The risk is that bundling every medium can blur the point if the controls stop feeling precise.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Krea 1 plus visual control handles', 'Creator Tools', 'Series B', '$47M', NULL, NULL, NULL, 'US', 'ai creative tools,image generation,video generation,design tools', 'Bain Capital Ventures, Andreessen Horowitz, Abstract Ventures', '{"github": "https://github.com/krea-ai", "twitter": "https://x.com/krea_ai", "linkedin": "https://www.linkedin.com/company/krea-ai"}', 1, 'krea.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lakefusion', 'lakefusion', 'www.lakefusion.ai', 'https://www.lakefusion.ai', 'LakeFusion', 'Databricks-native master data management for golden records.', 'The interesting move is refusing to be another MDM system outside the warehouse. LakeFusion installs through AWS or Azure Marketplace, runs inside Databricks, and uses LLM plus vector matching to create governed golden records under Unity Catalog. Unlike legacy match-rule projects, the bet is zero data egress, real-time sync back to source systems, and weeks-to-value. The risk is Databricks-native being a moat only if buyers already live there.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.lakefusion.ai", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/04/3286394/0/en/LakeFusion-Raises-7-5M-Seed-Financing-to-Redefine-Master-Data-Management-MDM-Natively-on-Databricks.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes LakeFusion: Databricks-native master data management for golden records.", "source_ids": ["official_site"]}, {"claim": "LakeFusion installs through AWS or Azure Marketplace, runs inside Databricks, and uses LLM plus vector matching to create governed golden records under Unity Catalog.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "$7.5M Seed for Databricks MDM", "why_now": "Recent source-backed funding and public product evidence make data management, databricks, mdm worth tracking."}, "risks": [{"claim": "The risk is Databricks-native being a moat only if buyers already live there.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$7.5M Seed for Databricks MDM', 'SaaS', 'Seed', '$7.5M', NULL, NULL, NULL, 'US', 'data management,databricks,mdm,ai', 'Silverton Partners', '{"linkedin": "https://www.linkedin.com/company/lakefusion-ai/"}', 1, 'lakefusion.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lexroom', 'lexroom', 'lexroom.ai', 'https://lexroom.ai/', 'Lexroom', 'Legal AI workspace for source-backed research, drafting, and private firm libraries.', 'Legal AI gets more credible when the source trail is the interface, not a footnote. Lexroom shows official-source research, document comparison, clause drafting, private libraries, original judgments, pricing, and more than 10,000 professional users. Unlike broad legal copilots that ask lawyers to trust a black box, it sells verifiability as the workflow.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://lexroom.ai/", "type": "official"}, {"id": "funding_1", "label": "Tech Funding News", "url": "https://techfundingnews.com/harvey-rival-lexroom-raises-50m-to-power-ai-for-europes-one-million-lawyers/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Lexroom: Legal AI workspace for source-backed research, drafting, and private firm libraries.", "source_ids": ["official_site"]}, {"claim": "Lexroom shows official-source research, document comparison, clause drafting, private libraries, original judgments, pricing, and more than 10,000 professional users.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Source-backed legal AI", "why_now": "Recent source-backed funding and public product evidence make legal ai, document drafting, research worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Source-backed legal AI', 'SaaS', 'Series B', '$50M', NULL, NULL, NULL, 'Europe', 'legal ai,document drafting,research,compliance,workflow', 'Left Lane Capital', NULL, 1, 'lexroom.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-linear', 'linear', 'linear.app', 'https://linear.app', 'Linear', 'Issue tracking built for modern software teams.', 'Someone finally rebuilt project management for teams that live on the keyboard. Keyboard shortcuts, a stripped-back issue flow, and an interface that stays out of the way make it feel closer to an editor than Jira. In a market full of feature-bloated software, Linear chose speed and restraint. That trade only works if you are willing to say no more often than your competitors.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://linear.app", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2025/06/10/atlassian-rival-linear-raises-82m-at-1-25b-valuation/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Linear: Issue tracking built for modern software teams.", "source_ids": ["official_site"]}, {"claim": "Someone finally rebuilt project management for teams that live on the keyboard.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Defined a new standard for dev tools", "why_now": "Recent source-backed funding and public product evidence make project management, issue tracking, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Defined a new standard for dev tools', 'DevTools', 'Series C', '$82M', 2019, '50-100', 'San Francisco', 'US', 'project management,issue tracking,developer tools,productivity', 'Sequoia Capital, 01 Advisors, SV Angel', '{"github": "https://github.com/linear", "twitter": "https://x.com/linear", "linkedin": "https://linkedin.com/company/linear"}', 1, 'linear.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-liquid-instruments', 'liquid-instruments', 'www.liquidinstruments.com', 'https://www.liquidinstruments.com', 'Liquid Instruments', 'Software-defined test instruments for engineering labs.', 'This is what test equipment looks like when software wins over the bench rack. Liquid Instruments turns Moku hardware into 15+ instruments, switches setups in seconds, and lets teams build custom measurement systems with FPGA-backed processing. Unlike another oscilloscope vendor, it treats instrumentation as a reconfigurable platform. The question is whether AI customization becomes a workflow, not just a lab upgrade.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.liquidinstruments.com", "type": "official"}, {"id": "funding_1", "label": "Liquid Instruments", "url": "https://liquidinstruments.com/news-updates/series-c/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Liquid Instruments: Software-defined test instruments for engineering labs.", "source_ids": ["official_site"]}, {"claim": "Liquid Instruments turns Moku hardware into 15+ instruments, switches setups in seconds, and lets teams build custom measurement systems with FPGA-backed processing.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "15+ instruments in one Moku", "why_now": "Recent source-backed funding and public product evidence make test equipment, instrumentation, fpga worth tracking."}, "risks": [{"claim": "The question is whether AI customization becomes a workflow, not just a lab upgrade.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '15+ instruments in one Moku', 'Other', 'Series C', '$50M', NULL, NULL, NULL, 'US', 'test equipment,instrumentation,fpga,engineering tools', 'Keysight Technologies', NULL, 1, 'liquid-instruments.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-manifest-os', 'manifest-os', 'manifestos.com', 'https://manifestos.com', 'Manifest OS', 'AI-native legal-services platform for fixed-fee immigration firms.', 'Someone finally attacked legal AI from the business model, not the Word add-in. Manifest OS powers immigration firms with fixed-fee pricing, a client portal, AI Drafter, AI Case Evaluation, and 3,000+ handled engagements. Unlike Harvey-style copilot tools, the bet is to operate the service stack and reinvest firm profits into R&D. The risk is bar-by-bar regulation slowing the model outside Arizona.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://manifestos.com", "type": "official"}, {"id": "funding_1", "label": "Business Wire", "url": "https://natlawreview.com/press-releases/manifest-os-raises-60m-scale-worlds-first-ai-native-law-firm-model", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Manifest OS: AI-native legal-services platform for fixed-fee immigration firms.", "source_ids": ["official_site"]}, {"claim": "Manifest OS powers immigration firms with fixed-fee pricing, a client portal, AI Drafter, AI Case Evaluation, and 3,000+ handled engagements.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "$60M Series A, 3,000+ engagements", "why_now": "Recent source-backed funding and public product evidence make legal tech, ai agents, immigration worth tracking."}, "risks": [{"claim": "The risk is bar-by-bar regulation slowing the model outside Arizona.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$60M Series A, 3,000+ engagements', 'Other', 'Series A', '$60M', NULL, NULL, NULL, 'US', 'legal tech,ai agents,immigration,services', 'Menlo Ventures', '{"linkedin": "https://www.linkedin.com/company/manifest-os/"}', 1, 'manifest-os.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-modal', 'modal', 'modal.com', 'https://modal.com/', 'Modal', 'Serverless compute platform for AI, GPU, sandbox, training, and data workloads.', 'The bet is that AI infrastructure should feel like importing a function, not reserving a cluster. Modal shows Python-defined cloud environments, docs, pricing, inference, training, sandboxes, 1000+ GPU autoscaling, and customer proof from Runway, Suno, and Physical Intelligence. Unlike cloud consoles built around machines, it makes the code boundary the control plane.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://modal.com/", "type": "official"}, {"id": "funding_1", "label": "Modal", "url": "https://modal.com/blog/modal-series-c", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Modal: Serverless compute platform for AI, GPU, sandbox, training, and data workloads.", "source_ids": ["official_site"]}, {"claim": "Modal shows Python-defined cloud environments, docs, pricing, inference, training, sandboxes, 1000+ GPU autoscaling, and customer proof from Runway, Suno, and Physical Intelligence.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Serverless GPU infra for AI", "why_now": "Recent source-backed funding and public product evidence make ai infrastructure, gpu, serverless worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Serverless GPU infra for AI', 'DevTools', 'Series C', '$355M', NULL, NULL, NULL, 'US', 'ai infrastructure,gpu,serverless,developer tools,data workloads', 'General Catalyst, Redpoint Ventures', NULL, 1, 'modal.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-moment-energy', 'moment-energy', 'www.momentenergy.com', 'https://www.momentenergy.com', 'Moment Energy', 'Second-life EV battery storage systems for commercial sites.', 'The better climate bet is not another new battery chemistry; it is making retired EV packs insurable infrastructure. Moment Energy leads with Luna BESS, UL 1974 and UL 9540A certifications, supply ties to Mercedes-Benz and Nissan, and an Austin factory plan. Unlike generic grid-storage pitches, the product choice is narrow: own the battery management layer so old packs can safely serve data centers and industrial sites.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.momentenergy.com", "type": "official"}, {"id": "funding_1", "label": "PRNewswire", "url": "https://www.prnewswire.com/news-releases/moment-energy-raises-us40m-series-b-to-build-the-worlds-largest-second-life-battery-factory-302762579.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Moment Energy: Second-life EV battery storage systems for commercial sites.", "source_ids": ["official_site"]}, {"claim": "Moment Energy leads with Luna BESS, UL 1974 and UL 9540A certifications, supply ties to Mercedes-Benz and Nissan, and an Austin factory plan.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Climate, infrastructure, or operations teams evaluating measurable sustainability workflows.", "category": "Climate / Sustainability", "differentiation": "Certified second-life BESS", "why_now": "Recent source-backed funding and public product evidence make battery storage, climate, energy infrastructure worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Certified second-life BESS', 'Climate / Sustainability', 'Series B', '$40M+', NULL, NULL, NULL, 'Global / Remote', 'battery storage,climate,energy infrastructure,ev batteries', 'Evok Innovations, Liberty Mutual Investments, W23 Global Fund, Acario', '{"twitter": "https://twitter.com/moment_energy", "linkedin": "https://ca.linkedin.com/company/momentenergy"}', 1, 'moment-energy.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-moment', 'moment', 'moment.com', 'https://moment.com', 'Moment', 'AI operating system for investment managers, advisors, portfolios, and trades.', 'The sharp bet is replacing the investment stack''s point tools instead of adding another advisor chatbot. Moment''s memo shows agents for proposals, restrictions, cash redemption, trade ideas, execution quality, reconciliation failures, and source data. Unlike generic wealth copilots, it is built around auditable portfolio actions. The risk is whether large firms let the OS become the workflow of record.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://moment.com", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/19/3297569/0/en/Moment-Raises-78-Million-as-Largest-Wealth-Firms-Standardize-on-its-AI-Operating-System-for-Investment-Management.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Moment: AI operating system for investment managers, advisors, portfolios, and trades.", "source_ids": ["official_site"]}, {"claim": "Moment''s memo shows agents for proposals, restrictions, cash redemption, trade ideas, execution quality, reconciliation failures, and source data.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "AI OS for portfolio work", "why_now": "Recent source-backed funding and public product evidence make fintech, investment management, ai agents worth tracking."}, "risks": [{"claim": "The risk is whether large firms let the OS become the workflow of record.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'AI OS for portfolio work', 'Fintech', 'Series C', '$78M', NULL, NULL, NULL, 'US', 'fintech,investment management,ai agents,wealthtech', 'Index Ventures, Andreessen Horowitz', NULL, 1, 'moment.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-monk', 'monk', 'monk.com', 'https://monk.com', 'Monk', 'AI accounts receivable platform for invoices, collections, cash application, and disputes.', 'The smart move is treating accounts receivable as customer infrastructure, not back-office nagging. Monk handles contract-to-cash work like invoice creation, collections, cash application, portal uploads, PO mismatches, and disputes, with reported 40% lower DSO. Unlike generic finance automation, the product is built around the ugly exceptions that actually delay cash. The risk is that services-heavy onboarding hides how much of the product is software.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://monk.com", "type": "official"}, {"id": "funding_1", "label": "Monk", "url": "https://monk.com/blog/monk-raises-25m", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Monk: AI accounts receivable platform for invoices, collections, cash application, and disputes.", "source_ids": ["official_site"]}, {"claim": "The smart move is treating accounts receivable as customer infrastructure, not back-office nagging.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "AR edge cases, not reminders", "why_now": "Recent source-backed funding and public product evidence make accounts receivable, finance automation, ai agents worth tracking."}, "risks": [{"claim": "The risk is that services-heavy onboarding hides how much of the product is software.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'AR edge cases, not reminders', 'Fintech', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'accounts receivable,finance automation,ai agents,b2b', 'Footwork', NULL, 1, 'monk.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-nanoclaw', 'nanoclaw', 'nanoclaw.dev', 'https://nanoclaw.dev/', 'NanoClaw', 'Container-isolated personal AI agent with messaging channels and per-agent workspaces.', 'The smart bet is shrinking personal agents until the security model is legible. NanoClaw exposes a Node host, per-agent Docker containers, per-session SQLite files, multi-channel skills, and Agent Vault credential injection. Unlike OpenClaw-style agents that sit on the host, it makes isolation the default product surface. The risk is whether implementation services pull it away from the open-source simplicity that made it spread.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://nanoclaw.dev/", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/20/nanoclaw-creator-turns-down-20m-buyout-offer-raises-12m-seed-instead/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes NanoClaw: Container-isolated personal AI agent with messaging channels and per-agent workspaces.", "source_ids": ["official_site"]}, {"claim": "NanoClaw exposes a Node host, per-agent Docker containers, per-session SQLite files, multi-channel skills, and Agent Vault credential injection.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Per-agent Docker isolation", "why_now": "Recent source-backed funding and public product evidence make ai agents, developer tools, security worth tracking."}, "risks": [{"claim": "The risk is whether implementation services pull it away from the open-source simplicity that made it spread.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Per-agent Docker isolation', 'DevTools', 'Seed', '$12M', NULL, NULL, NULL, 'US', 'ai agents,developer tools,security,open source', 'Valley Capital Partners', '{"github": "https://github.com/nanocoai/nanoclaw", "twitter": "https://x.com/Gavriel_Cohen"}', 1, 'nanoclaw.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-nectar-social', 'nectar-social', 'www.nectarsocial.com', 'https://www.nectarsocial.com', 'Nectar Social', 'AI social operating system for community management, listening, and attribution.', 'Someone finally treated social replies as checkout infrastructure instead of brand theater. Nectar shows AI agents for DMs, comments, creator workflows, Reddit/Meta data, 95% untagged conversations, and revenue attribution in one workspace. Unlike Hootsuite-style schedulers, it bets that the community manager''s inbox is where demand is created. The hard part is keeping brand voice from turning into customer-service mush.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.nectarsocial.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/16/marketing-operating-system-nectar-social-raises-30m-series-a-in-round-led-by-menlo/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Nectar Social: AI social operating system for community management, listening, and attribution.", "source_ids": ["official_site"]}, {"claim": "Nectar shows AI agents for DMs, comments, creator workflows, Reddit/Meta data, 95% untagged conversations, and revenue attribution in one workspace.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "95% untagged social coverage", "why_now": "Recent source-backed funding and public product evidence make social commerce, ai agents, community management worth tracking."}, "risks": [{"claim": "The hard part is keeping brand voice from turning into customer-service mush.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '95% untagged social coverage', 'SaaS', 'Series A', '$30M', NULL, NULL, NULL, 'US', 'social commerce,ai agents,community management,marketing analytics', 'Menlo Ventures', '{"linkedin": "https://www.linkedin.com/company/nectar-ai"}', 1, 'nectar-social.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ocean', 'ocean', 'ocean.security', 'https://ocean.security/platform', 'Ocean', 'Agentic email security that investigates messages before they reach the inbox.', 'The sharp idea is moving phishing triage before the inbox instead of polishing the abuse queue. Ocean''s Ray engine coordinates link, identity, file, financial, and quarantine agents, then returns an explainable verdict to employees across Microsoft 365 and Google Workspace. Unlike SEG filters that score and shrug, it tries to investigate every email as a live case. The buyer risk is trusting an agent between fraud and false positive.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://ocean.security/platform", "type": "official"}, {"id": "funding_1", "label": "CTech", "url": "https://www.calcalistech.com/ctechnews/article/sj59xf5jml", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Ocean: Agentic email security that investigates messages before they reach the inbox.", "source_ids": ["official_site"]}, {"claim": "Ocean''s Ray engine coordinates link, identity, file, financial, and quarantine agents, then returns an explainable verdict to employees across Microsoft 365 and Google Workspace.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Agent swarm before inbox", "why_now": "Recent source-backed funding and public product evidence make cybersecurity, email security, ai agents worth tracking."}, "risks": [{"claim": "The buyer risk is trusting an agent between fraud and false positive.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Agent swarm before inbox', 'AI / ML', 'Series A', '$20M', NULL, NULL, NULL, 'Global / Remote', 'cybersecurity,email security,ai agents,phishing', 'Lightspeed Venture Partners', NULL, 1, 'ocean.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-origin-lab', 'origin-lab', 'originlab.ai', 'https://originlab.ai', 'Origin Lab', 'Licensed game-engine data for AI world models and robotics simulation.', 'The interesting bet is that world models need game-engine state, not scraped video. Origin Lab captures HUD-free gameplay with depth, action, camera, scene metadata, 20+ categories, 50+ licensed titles, and same-day API access for evals. Compared with web video datasets, this has rights provenance and physics-adjacent telemetry. The hard part is whether game worlds transfer to messy real-world robotics.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://originlab.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/13/origin-lab-raises-8m-to-help-video-game-companies-sell-data-to-world-model-builders/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Origin Lab: Licensed game-engine data for AI world models and robotics simulation.", "source_ids": ["official_site"]}, {"claim": "Origin Lab captures HUD-free gameplay with depth, action, camera, scene metadata, 20+ categories, 50+ licensed titles, and same-day API access for evals.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Game-engine data for world models", "why_now": "Recent source-backed funding and public product evidence make world models, training data, video games worth tracking."}, "risks": [{"claim": "The hard part is whether game worlds transfer to messy real-world robotics.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Game-engine data for world models', 'AI / ML', 'Seed', '$8M', NULL, NULL, NULL, 'US', 'world models,training data,video games,synthetic data', 'Lightspeed Venture Partners', NULL, 0, 'origin-lab.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-outmarket', 'outmarket', 'outmarket.ai', 'https://outmarket.ai', 'Outmarket', 'AI workflow platform for insurance brokerages.', 'The smart move is treating insurance brokerage as document ops, not generic CRM automation. Outmarket shows quote comparison, gap analysis, ACORD forms, AMS360/Applied Epic integrations, 250+ agencies, and 12-15 hours saved per person each week. Unlike broad AI copilots, the bet is that brokers will trust software embedded in policy workflows. The risk is whether specialty lines keep needing human edge cases.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://outmarket.ai", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/outmarket-ai-raises-17m-series-a-to-power-the-intelligence-era-of-insurance-302770379.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Outmarket: AI workflow platform for insurance brokerages.", "source_ids": ["official_site"]}, {"claim": "Outmarket shows quote comparison, gap analysis, ACORD forms, AMS360/Applied Epic integrations, 250+ agencies, and 12-15 hours saved per person each week.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "250+ agencies, $17M Series A", "why_now": "Recent source-backed funding and public product evidence make insurance, ai workflows, brokerages worth tracking."}, "risks": [{"claim": "The risk is whether specialty lines keep needing human edge cases.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '250+ agencies, $17M Series A', 'Fintech', 'Series A', '$17M', NULL, NULL, NULL, 'US', 'insurance,ai workflows,brokerages,document automation', 'Permanent Capital Ventures', NULL, 1, 'outmarket.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-parallel-web-systems', 'parallel-web-systems', 'parallel.ai', 'https://parallel.ai', 'Parallel Web Systems', 'Web search, extraction, monitoring, and research APIs for AI agents.', 'The sharper bet is that AI agents need web infrastructure, not another consumer search box. Parallel exposes Search, Extract, Task, FindAll, Chat, and Monitor APIs, plus OpenAPI, Python, and TypeScript SDKs. Unlike browser wrappers that pretend pages are stable, this treats the web as a programmatic substrate with benchmarks and case studies attached. The risk is that model providers pull the same interfaces into their own platforms.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://parallel.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/29/parallel-web-systems-hits-2b-valuation-five-months-after-its-last-big-raise/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Parallel Web Systems: Web search, extraction, monitoring, and research APIs for AI agents.", "source_ids": ["official_site"]}, {"claim": "VentureDex product review notes that unlike browser wrappers that pretend pages are stable, this treats the web as a programmatic substrate with benchmarks and case studies attached.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Web APIs for AI agents", "why_now": "Recent source-backed funding and public product evidence make ai agents, web search, api worth tracking."}, "risks": [{"claim": "The risk is that model providers pull the same interfaces into their own platforms.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Web APIs for AI agents', 'DevTools', 'Series B', '$100M', 2023, '10-30', 'San Francisco', 'US', 'ai agents,web search,api,developer tools', 'Sequoia Capital, Index Ventures, Khosla Ventures', '{"github": "https://github.com/parallel-web", "twitter": "https://x.com/p0", "linkedin": "https://www.linkedin.com/company/parallel-web/"}', 1, 'parallel-web-systems.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-parasail', 'parasail', 'parasail.io', 'https://parasail.io', 'Parasail', 'Serverless and dedicated GPU inference for AI teams.', 'The practical bet is inference without the cloud procurement tax. Parasail leads with no quotas, no long contracts, up to 30x lower pricing, and docs for Serverless, Dedicated endpoints, Batch, Responses API, and billing APIs. Compared to renting raw GPU boxes, it sells a model-running surface that can scale from free credits to 500B+ daily tokens. The open question is whether this stays cheaper once the largest clouds copy the packaging.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://parasail.io", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/15/parasail-raises-32m-to-feed-tokenmaxxing-ai-developers/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Parasail: Serverless and dedicated GPU inference for AI teams.", "source_ids": ["official_site"]}, {"claim": "Parasail leads with no quotas, no long contracts, up to 30x lower pricing, and docs for Serverless, Dedicated endpoints, Batch, Responses API, and billing APIs.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "500B+ tokens served daily", "why_now": "Recent source-backed funding and public product evidence make gpu cloud, inference, ai infrastructure worth tracking."}, "risks": [{"claim": "The open question is whether this stays cheaper once the largest clouds copy the packaging.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '500B+ tokens served daily', 'DevTools', 'Series A', '$32M', 2023, '10-30', 'San Francisco', 'US', 'gpu cloud,inference,ai infrastructure,developer tools', 'Touring Capital, Kindred Ventures, Basis Set, Samsung Next', '{"twitter": "https://x.com/parasail_io", "linkedin": "https://www.linkedin.com/company/parasail-io/"}', 1, 'parasail.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-perplexity', 'perplexity', 'perplexity.ai', 'https://perplexity.ai', 'Perplexity', 'AI-powered answer engine that searches the web.', 'Answer-first search should have existed years ago. Perplexity makes the core interaction brutally simple: ask a question, get a synthesized answer with sources, not ten blue links and ad clutter. That is a sharp product bet against the browsing-heavy search interface. The open question is whether that habit expands beyond power users.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://perplexity.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2024/01/04/ai-powered-search-engine-perplexity-ai-now-valued-at-520m-raises-70m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Perplexity: AI-powered answer engine that searches the web.", "source_ids": ["official_site"]}, {"claim": "Answer-first search should have existed years ago.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "The Google killer that might actually be", "why_now": "Recent source-backed funding and public product evidence make ai search, answer engine, web search worth tracking."}, "risks": [{"claim": "The open question is whether that habit expands beyond power users.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'The Google killer that might actually be', 'AI / ML', 'Series B', '$73.6M', 2022, '100-200', 'San Francisco', 'US', 'ai search,answer engine,web search,artificial intelligence', 'IVP, NEA, Databricks Ventures, Jeff Bezos', '{"twitter": "https://x.com/perabordar", "linkedin": "https://linkedin.com/company/perplexity-ai"}', 1, 'perplexity.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pit', 'pit', 'pit.com', 'https://pit.com', 'Pit', 'AI-built internal software for enterprise workflows.', 'The interesting bet is that enterprise software should be generated around the workflow, not bought as another SaaS shelf. Pit Studio maps messy processes, while Pit Cloud promises governance, audit trails, SSO, and tenant isolation for the custom apps it builds. Compared with no-code builders or agent sandboxes, this is closer to a forward-deployed product team. The risk is that every bespoke workflow can become consulting debt.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://pit.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/07/voi-founders-new-ai-startup-pit-has-become-the-latest-rising-star-out-of-stockholm/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Pit: AI-built internal software for enterprise workflows.", "source_ids": ["official_site"]}, {"claim": "Pit Studio maps messy processes, while Pit Cloud promises governance, audit trails, SSO, and tenant isolation for the custom apps it builds.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "$16M seed for AI-built ops software", "why_now": "Recent source-backed funding and public product evidence make enterprise ai, workflow automation, internal tools worth tracking."}, "risks": [{"claim": "The risk is that every bespoke workflow can become consulting debt.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$16M seed for AI-built ops software', 'SaaS', 'Seed', '$16M', NULL, NULL, NULL, 'Europe', 'enterprise ai,workflow automation,internal tools,operations', 'Andreessen Horowitz, Lakestar', NULL, 1, 'pit.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pivot', 'pivot', 'home.pivotapp.ai', 'https://home.pivotapp.ai', 'Pivot', 'AI procurement OS for intake, committed spend, workflows, and negotiation.', 'The bet is turning procurement into a governed operating layer instead of a nicer intake form. Pivot exposes request workflows, committed-spend visibility, AI Studio, ERP connections, and source-to-pay automation for buyers like DoorDash and Lemonade. Unlike point tools that stop at approvals, it tries to keep finance discipline attached to every request. The risk is whether legacy procurement data is clean enough for agents to act.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://home.pivotapp.ai", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/21/3299278/0/en/pivot-raises-40-million-series-b-to-replace-legacy-procurement-software-with-an-enterprise-ai-operating-system.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Pivot: AI procurement OS for intake, committed spend, workflows, and negotiation.", "source_ids": ["official_site"]}, {"claim": "Pivot exposes request workflows, committed-spend visibility, AI Studio, ERP connections, and source-to-pay automation for buyers like DoorDash and Lemonade.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Procurement agents with controls", "why_now": "Recent source-backed funding and public product evidence make procurement, ai agents, erp worth tracking."}, "risks": [{"claim": "The risk is whether legacy procurement data is clean enough for agents to act.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Procurement agents with controls', 'SaaS', 'Series B', '$40M', NULL, NULL, NULL, 'US', 'procurement,ai agents,erp,spend management', 'Forestay Capital, Notion Capital', NULL, 1, 'pivot.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-qodo', 'qodo', 'www.qodo.ai', 'https://www.qodo.ai', 'Qodo', 'AI code review, testing, and governance for engineering teams.', 'Most AI coding products still want to be copilots; the cleaner bet is fixing the review bottleneck instead. Qodo leads with 856.5K VS Code installs, 625K JetBrains installs, and a workflow spanning IDE, PR, CLI, and rules. That review-first posture feels more durable than one more generator wrapper, because teams adopting AI fastest mostly need help trusting what already got written. The risk is that model vendors eventually bundle enough verification to squeeze the middle layer.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.qodo.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/03/30/qodo-bets-on-code-verification-as-ai-coding-scales-raises-70m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Qodo: AI code review, testing, and governance for engineering teams.", "source_ids": ["official_site"]}, {"claim": "Qodo leads with 856.5K VS Code installs, 625K JetBrains installs, and a workflow spanning IDE, PR, CLI, and rules.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Review-first AI coding workflow", "why_now": "Recent source-backed funding and public product evidence make developer tools, code review, ai coding worth tracking."}, "risks": [{"claim": "The risk is that model vendors eventually bundle enough verification to squeeze the middle layer.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Review-first AI coding workflow', 'DevTools', 'Series B', '$70M', 2022, NULL, 'New York', 'US', 'developer tools,code review,ai coding,software quality', 'Qumra Capital, Maor Ventures, Phoenix Venture Partners, S Ventures, Square Peg, Susa Ventures, TLV Partners, Vine Ventures', '{"github": "https://github.com/Codium-ai", "twitter": "https://x.com/QodoAI", "linkedin": "https://www.linkedin.com/company/qodoai"}', 1, 'qodo.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-quantware', 'quantware', 'quantware.com', 'https://quantware.com', 'QuantWare', 'Commercial QPUs, peripherals, and foundry services for quantum builders.', 'The sharper quantum bet is not selling one more lab chip; it is turning QPUs into a manufacturable supply chain. QuantWare sells A-Line, D-Line, peripherals, foundry, and packaging services, and says it has shipped to 50+ customers across 20 countries. Unlike full-stack quantum computer builders, VIO is a component-platform wager: own the processor architecture other teams scale on. The risk is that the 10,000-qubit 2028 promise still has to survive physics and factory reality.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://quantware.com", "type": "official"}, {"id": "funding_1", "label": "Bloomberg", "url": "https://www.bloomberg.com/news/articles/2026-05-05/intel-capital-backs-quantum-computing-chips-startup-quantware", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes QuantWare: Commercial QPUs, peripherals, and foundry services for quantum builders.", "source_ids": ["official_site"]}, {"claim": "QuantWare sells A-Line, D-Line, peripherals, foundry, and packaging services, and says it has shipped to 50+ customers across 20 countries.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "Open QPU supply chain", "why_now": "Recent source-backed funding and public product evidence make quantum, hardware, qpu worth tracking."}, "risks": [{"claim": "The risk is that the 10,000-qubit 2028 promise still has to survive physics and factory reality.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Open QPU supply chain', 'Other', 'Series B', '$178M', NULL, NULL, NULL, 'Europe', 'quantum,hardware,qpu,semiconductors', 'Intel Capital, IQT, ETF Partners, FORWARD.one, Invest-NL Deep Tech Fund, InnovationQuarter Capital, Ground State Ventures, Graduate Ventures', '{"linkedin": "https://www.linkedin.com/company/quantware"}', 1, 'quantware.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-quartermaster', 'quartermaster', 'www.quartermaster.us', 'https://www.quartermaster.us/', 'Quartermaster', 'SmartMast sensors and AI turn commercial vessels into a maritime awareness network.', 'The useful bet is turning ordinary ships into a sensing network instead of selling another fleet dashboard. Quartermaster puts SmartMast cameras, radios, geolocation, and AI on 600+ vessels, then shows verified HD video, alerts, and real-time tracking. Compared with AIS pings, the product captures what ships actually see. The risk is whether network coverage scales faster than hardware installation drag.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.quartermaster.us/", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/20/this-startup-raised-43m-to-build-a-hive-mind-for-ships/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Quartermaster: SmartMast sensors and AI turn commercial vessels into a maritime awareness network.", "source_ids": ["official_site"]}, {"claim": "Quartermaster puts SmartMast cameras, radios, geolocation, and AI on 600+ vessels, then shows verified HD video, alerts, and real-time tracking.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "600+ ships sensing oceans", "why_now": "Recent source-backed funding and public product evidence make maritime, sensors, ai worth tracking."}, "risks": [{"claim": "The risk is whether network coverage scales faster than hardware installation drag.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '600+ ships sensing oceans', 'Other', 'Series A', '$43M', NULL, NULL, NULL, 'US', 'maritime,sensors,ai,transportation', 'First Round Capital, Quiet Capital', NULL, 1, 'quartermaster.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-radixark', 'radixark', 'www.radixark.com', 'https://www.radixark.com', 'RadixArk', 'Open inference and training infrastructure for frontier AI.', 'The useful bet is that AI infra should be shared infrastructure, not private lab plumbing. RadixArk starts from SGLang for inference and Miles for post-training, with SGLang already powering trillions of tokens daily across teams like Google, NVIDIA, Oracle, AMD, LinkedIn, and xAI. Compared with another closed model platform, this is a tools-and-runtime company. The risk is turning open-source gravity into a managed product without slowing the community.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.radixark.com", "type": "official"}, {"id": "funding_1", "label": "RadixArk", "url": "https://www.radixark.com/blog/radixark-launches-100m-seed", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes RadixArk: Open inference and training infrastructure for frontier AI.", "source_ids": ["official_site"]}, {"claim": "RadixArk starts from SGLang for inference and Miles for post-training, with SGLang already powering trillions of tokens daily across teams like Google, NVIDIA, Oracle, AMD, LinkedIn, and xAI.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "$100M seed for SGLang infra", "why_now": "Recent source-backed funding and public product evidence make ai infrastructure, inference, open source worth tracking."}, "risks": [{"claim": "The risk is turning open-source gravity into a managed product without slowing the community.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$100M seed for SGLang infra', 'DevTools', 'Seed', '$100M', NULL, NULL, NULL, 'US', 'ai infrastructure,inference,open source,developer tools', 'Accel, Spark Capital, NVentures, Salience Capital, A&E Investment, HOF Capital, Walden Catalyst, AMD, LDVP, WTT Fubon Family, MediaTek, Databricks', '{"github": "https://github.com/radixark"}', 1, 'radixark.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-rely', 'rely', 'tryrely.ai', 'https://tryrely.ai', 'Rely', 'AI diligence automation for multifamily lease, vendor, utility, and financial audits.', 'This is deal-room software with the spreadsheet pain left in view. Rely ingests multifamily leases, vendor contracts, utilities, and financial files, then exports source-linked audit tables in under 30 minutes for most reviews. Unlike generic document AI, it bets on one messy asset class and one due-diligence workflow. The open question is whether lenders and operators trust the model when a single bad cell changes a deal.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://tryrely.ai", "type": "official"}, {"id": "funding_1", "label": "Commercial Observer", "url": "https://commercialobserver.com/2026/05/multifamily-deal-diligence-rely-fundraise/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Rely: AI diligence automation for multifamily lease, vendor, utility, and financial audits.", "source_ids": ["official_site"]}, {"claim": "Rely ingests multifamily leases, vendor contracts, utilities, and financial files, then exports source-linked audit tables in under 30 minutes for most reviews.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Under-30-minute audits", "why_now": "Recent source-backed funding and public product evidence make proptech, due diligence, document ai worth tracking."}, "risks": [{"claim": "The open question is whether lenders and operators trust the model when a single bad cell changes a deal.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Under-30-minute audits', 'SaaS', 'Seed', '$4.5M', NULL, NULL, NULL, 'US', 'proptech,due diligence,document ai,multifamily', '2048 Ventures', NULL, 1, 'rely.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-resend', 'resend', 'resend.com', 'https://resend.com', 'Resend', 'Email API for developers. Beautiful, simple, reliable.', 'Transactional email used to feel like plumbing you tolerated, not a product you enjoyed. Resend changed that with a cleaner API surface and React Email as a companion project. That pairing reveals the bet: email delivery and email design should live in the same developer workflow. It feels closer to Stripe-grade DX than legacy SMTP tooling.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://resend.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2023/07/18/developer-focused-email-platform-resend-raises-3m/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Resend: Email API for developers. Beautiful, simple, reliable.", "source_ids": ["official_site"]}, {"claim": "Resend changed that with a cleaner API surface and React Email as a companion project.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "DX that makes you jealous", "why_now": "Recent source-backed funding and public product evidence make email, api, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'DX that makes you jealous', 'DevTools', 'Seed', '$3M', 2022, '10-30', 'San Francisco', 'US', 'email,api,developer tools,transactional email', 'Y Combinator, SV Angel, Dylan Field', '{"github": "https://github.com/resend", "twitter": "https://x.com/resabordar", "linkedin": "https://linkedin.com/company/resend"}', 1, 'resend.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-scout-space', 'scout-space', 'www.scout.space', 'https://www.scout.space', 'Scout Space', 'In-space sensors and autonomy software for orbital awareness.', 'The sharp part is that space awareness needs distributed eyes in orbit, not only bigger ground systems. Scout Space sells Owl sensors, mission autonomy software, edge processing, and data tools for operators, and this round funds a 2,600-square-foot Virginia facility. Compared with a pure satellite builder, it is trying to become the sensing layer other spacecraft can carry. The risk is that government demand may hide how repeatable the commercial workflow is.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.scout.space", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/scout-space-raises-18m-series-a-to-scale-space-domain-awareness-capabilities-and-expand-manufacturing-in-northern-virginia-302760326.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Scout Space: In-space sensors and autonomy software for orbital awareness.", "source_ids": ["official_site"]}, {"claim": "Scout Space sells Owl sensors, mission autonomy software, edge processing, and data tools for operators, and this round funds a 2,600-square-foot Virginia facility.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "$18M Series A for orbital sensors", "why_now": "Recent source-backed funding and public product evidence make space, orbital awareness, sensors worth tracking."}, "risks": [{"claim": "The risk is that government demand may hide how repeatable the commercial workflow is.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$18M Series A for orbital sensors', 'Other', 'Series A', '$18M', NULL, NULL, NULL, 'US', 'space,orbital awareness,sensors,autonomy', 'Washington Harbour Partners, Virginia Innovation Partnership Corporation, Noblis Ventures, Decisive Point, Fusion Fund', '{"linkedin": "https://www.linkedin.com/company/scoutdotspace"}', 1, 'scout-space.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-secludy', 'secludy', 'secludy.com', 'https://secludy.com', 'Secludy', 'Privacy-safe synthetic data for regulated AI training.', 'The bet is that regulated AI teams need usable fake data, not another masking rulebook. Secludy shows differential-privacy presets, text and table anonymization examples, canary PII leakage tests, self-hosted VPC/on-prem deployment, and a claimed under-1-hour setup. Unlike legacy masking, it tries to preserve model utility while moving sensitive records out of scope. The risk is that privacy budgets become another specialist bottleneck.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://secludy.com", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/13/3294051/0/en/secludy-raises-4m-to-safely-unlock-proprietary-data-for-genai.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Secludy: Privacy-safe synthetic data for regulated AI training.", "source_ids": ["official_site"]}, {"claim": "Secludy shows differential-privacy presets, text and table anonymization examples, canary PII leakage tests, self-hosted VPC/on-prem deployment, and a claimed under-1-hour setup.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "$4M seed for DP synthetic data", "why_now": "Recent source-backed funding and public product evidence make synthetic data, privacy, ai training worth tracking."}, "risks": [{"claim": "The risk is that privacy budgets become another specialist bottleneck.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$4M seed for DP synthetic data', 'AI / ML', 'Seed', '$4M', NULL, NULL, NULL, 'US', 'synthetic data,privacy,ai training,regulated data', 'Impression Ventures', NULL, 1, 'secludy.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-shapes', 'shapes', 'talk.shapes.inc', 'https://talk.shapes.inc', 'Shapes', 'Social AI chat app where people and bots share group conversations.', 'Most AI companion apps trap users in one-on-one confession booths; this points the format back toward messy group chat. The public surface shows 300+ models, message counts like 86.8K on individual characters, and mobile app links instead of a blank waitlist. That choice makes AI feel closer to Discord roleplay than a therapist clone. The hard part is moderation: social AI gets more interesting exactly where it gets harder to keep safe.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://talk.shapes.inc", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/04/29/meet-shapes-the-app-bringing-humans-and-ai-into-the-same-group-chats/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Shapes: Social AI chat app where people and bots share group conversations.", "source_ids": ["official_site"]}, {"claim": "Most AI companion apps trap users in one-on-one confession booths; this points the format back toward messy group chat.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "AI companions in group chat", "why_now": "Recent source-backed funding and public product evidence make social ai, chat, consumer worth tracking."}, "risks": [{"claim": "The hard part is moderation: social AI gets more interesting exactly where it gets harder to keep safe.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'AI companions in group chat', 'AI / ML', 'Seed', '$8M', 2023, '10-30', 'San Francisco', 'US', 'social ai,chat,consumer,ai companions', 'Lightspeed Venture Partners, Betaworks, Hartbeat Ventures, The Games Fund', NULL, 1, 'shapes.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-shyld-ai', 'shyld-ai', 'www.shyld.ai', 'https://www.shyld.ai', 'Shyld AI', 'Physical AI agents for hospital operations and disinfection.', 'The real bet is that hospital AI should act in the room, not sit in the chart. Shyld AI shows 3D LiDAR, radar, infrared sensing, edge GPUs, UV-C cycles, and a Stanford-linked 93% contamination reduction claim. Unlike ambient scribes, this is physical AI that changes OR turnover and infection-control workflows. The risk is whether hospital deployment speed matches the clinical evidence.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.shyld.ai", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/14/3295222/0/en/shyld-ai-raises-13-4m-to-expand-active-ai-across-u-s-hospitals.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Shyld AI: Physical AI agents for hospital operations and disinfection.", "source_ids": ["official_site"]}, {"claim": "Shyld AI shows 3D LiDAR, radar, infrared sensing, edge GPUs, UV-C cycles, and a Stanford-linked 93% contamination reduction claim.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Healthcare, benefits, or life-sciences teams evaluating regulated operational workflows.", "category": "HealthTech", "differentiation": "93% contamination reduction", "why_now": "Recent source-backed funding and public product evidence make hospital operations, physical ai, infection control worth tracking."}, "risks": [{"claim": "The risk is whether hospital deployment speed matches the clinical evidence.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '93% contamination reduction', 'HealthTech', 'Seed', '$13.4M', NULL, NULL, NULL, 'US', 'hospital operations,physical ai,infection control,edge ai', 'Aulis Capital', NULL, 1, 'shyld-ai.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-socket', 'socket', 'socket.dev', 'https://socket.dev', 'Socket', 'Supply-chain security that blocks malicious open-source packages before install.', 'The interesting bet is moving supply-chain defense into the package-install path instead of another alert queue. Socket ships a GitHub app, CLI firewall, and reachability analysis that can block malicious npm packages before they land. Unlike SCA tools that mostly rank CVEs, it treats package behavior as the product surface. The risk is whether security teams trust a blocker in every developer workflow.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://socket.dev", "type": "official"}, {"id": "funding_1", "label": "Cooley", "url": "https://www.cooley.com/news/coverage/2026/2026-05-20-socket-raises-%2460-million-series-c-at-%241-billion-valuation", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Socket: Supply-chain security that blocks malicious open-source packages before install.", "source_ids": ["official_site"]}, {"claim": "Socket ships a GitHub app, CLI firewall, and reachability analysis that can block malicious npm packages before they land.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Install-time package firewall", "why_now": "Recent source-backed funding and public product evidence make cybersecurity, developer tools, supply chain worth tracking."}, "risks": [{"claim": "The risk is whether security teams trust a blocker in every developer workflow.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Install-time package firewall', 'DevTools', 'Series C', '$60M', NULL, NULL, NULL, 'US', 'cybersecurity,developer tools,supply chain,open source', 'Thrive Capital', NULL, 1, 'socket.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-stilta', 'stilta', 'www.stilta.com', 'https://www.stilta.com', 'Stilta', 'AI agents for patent invalidity, infringement, and freedom-to-operate analysis.', 'The smart move is treating patent analysis as evidence mapping, not legal chat. Stilta breaks work into infringement, invalidity, and FTO modules, then maps claim elements to patents, scientific literature, and archived web sources. Unlike generic legal copilots, it narrows the agent to questions attorneys already know how to audit. The risk is whether benchmark recall survives hostile expert review.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.stilta.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/19/legal-tech-announced-stilta-announces-10m-seed-backed-by-yc-and-a16z-months-after-launch/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Stilta: AI agents for patent invalidity, infringement, and freedom-to-operate analysis.", "source_ids": ["official_site"]}, {"claim": "Stilta breaks work into infringement, invalidity, and FTO modules, then maps claim elements to patents, scientific literature, and archived web sources.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "AI builders and operators evaluating model, automation, or data workflows.", "category": "AI / ML", "differentiation": "Patent claim evidence maps", "why_now": "Recent source-backed funding and public product evidence make legal tech, patents, ai agents worth tracking."}, "risks": [{"claim": "The risk is whether benchmark recall survives hostile expert review.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Patent claim evidence maps', 'AI / ML', 'Seed', '$10.5M', NULL, NULL, NULL, 'Europe', 'legal tech,patents,ai agents,litigation', 'Andreessen Horowitz, Y Combinator', NULL, 1, 'stilta.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-stitch', 'stitch', 'www.stitch.co', 'https://www.stitch.co', 'Stitch', 'Financial infrastructure OS for banks and fintechs.', 'The interesting move is treating bank modernization as a system-of-record problem, not a prettier payments API. Stitch exposes lending, cards, deposits, ledgers, applications, and live loan UI states, with $5B transacted in six months. Unlike point fintech rails, the bet is one stack that can be adopted module by module. The hard part is selling core infrastructure without inheriting every legacy edge case.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.stitch.co", "type": "official"}, {"id": "funding_1", "label": "Stitch", "url": "https://www.stitch.co/press/stitch-raises-25m-series-a-led-by-andreessen-horowitz", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Stitch: Financial infrastructure OS for banks and fintechs.", "source_ids": ["official_site"]}, {"claim": "Stitch exposes lending, cards, deposits, ledgers, applications, and live loan UI states, with $5B transacted in six months.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "$5B transacted in six months", "why_now": "Recent source-backed funding and public product evidence make financial infrastructure, core banking, ledgers worth tracking."}, "risks": [{"claim": "The hard part is selling core infrastructure without inheriting every legacy edge case.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '$5B transacted in six months', 'Fintech', 'Series A', '$25M', NULL, NULL, NULL, 'Global / Remote', 'financial infrastructure,core banking,ledgers,cards,lending', 'Andreessen Horowitz', NULL, 1, 'stitch.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-supabase', 'supabase', 'supabase.com', 'https://supabase.com', 'Supabase', 'The open source Firebase alternative.', 'The clever part is not calling itself an open-source Firebase alternative. The clever part is turning Postgres into the center of an entire developer stack: auth, storage, realtime, and edge functions. Where most backend platforms hide the database behind abstractions, Supabase leans into it. That makes the product more opinionated and easier to reason about than a generic backend cloud.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://supabase.com", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2022/05/10/supabase-raises-80m-series-b-for-its-open-source-firebase-alternative/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Supabase: The open source Firebase alternative.", "source_ids": ["official_site"]}, {"claim": "Where most backend platforms hide the database behind abstractions, Supabase leans into it.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Postgres as a platform", "why_now": "Recent source-backed funding and public product evidence make database, open source, backend worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Postgres as a platform', 'DevTools', 'Series B', '$80M', 2020, '100-200', 'Singapore', 'Global / Remote', 'database,open source,backend,postgres,firebase alternative', 'Felicis Ventures, Coatue Management, Y Combinator', '{"github": "https://github.com/supabase", "twitter": "https://x.com/supabase", "linkedin": "https://linkedin.com/company/supabase"}', 0, 'supabase.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-synera', 'synera', 'www.synera.io', 'https://www.synera.io', 'Synera', 'Agent platform for engineering workflows across CAD, FEA, costing, and reporting tools.', 'The interesting bet is that engineers do not need another copilot; they need a workbench where agents can operate CAD, FEA, cost, and reporting tools. Synera connects 80+ hardware-engineering systems with a node-based editor, 3D viewer, custom nodes, Python scripts, and token licensing. Unlike generic AI-for-manufacturing pitches, this starts from the messy CAx toolchain. The risk is that enterprise deployment turns the agents into services work.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.synera.io", "type": "official"}, {"id": "funding_1", "label": "Synera", "url": "https://www.synera.io/press/synera-raises-40m-series-b-to-scale-agentic-ai-engineering-for-global-manufacturers", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Synera: Agent platform for engineering workflows across CAD, FEA, costing, and reporting tools.", "source_ids": ["official_site"]}, {"claim": "Synera connects 80+ hardware-engineering systems with a node-based editor, 3D viewer, custom nodes, Python scripts, and token licensing.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "Agents across 80+ engineering tools", "why_now": "Recent source-backed funding and public product evidence make engineering, ai agents, cad worth tracking."}, "risks": [{"claim": "The risk is that enterprise deployment turns the agents into services work.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, 'Agents across 80+ engineering tools', 'SaaS', 'Series B', '$40M', NULL, NULL, NULL, 'Europe', 'engineering,ai agents,cad,industrial software', 'Revaia', NULL, 1, 'synera.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-texture', 'texture', 'www.texturehq.com', 'https://www.texturehq.com', 'Texture', 'Grid operating system for DER visibility, dispatch, telemetry, and settlements.', 'The smart bet is making grid operations a live data system instead of another utility dashboard. Texture models source AMI and SCADA data across devices, meters, transformers, and feeders, then runs dispatch, telemetry, notifications, and settlement workflows. Unlike generic climate SaaS, the product is tied to utility operations and VPP fleets. The risk is integration drag across every local grid stack.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.texturehq.com", "type": "official"}, {"id": "funding_1", "label": "Texture", "url": "https://www.texturehq.com/blog/texture-series-a", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Texture: Grid operating system for DER visibility, dispatch, telemetry, and settlements.", "source_ids": ["official_site"]}, {"claim": "Texture models source AMI and SCADA data across devices, meters, transformers, and feeders, then runs dispatch, telemetry, notifications, and settlement workflows.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Climate, infrastructure, or operations teams evaluating measurable sustainability workflows.", "category": "Climate / Sustainability", "differentiation": "Live grid operations OS", "why_now": "Recent source-backed funding and public product evidence make energy, grid operations, climate worth tracking."}, "risks": [{"claim": "The risk is integration drag across every local grid stack.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Live grid operations OS', 'Climate / Sustainability', 'Series A', '$12.5M', NULL, NULL, NULL, 'US', 'energy,grid operations,climate,utility software', 'VoLo Earth Ventures, Equal Ventures', NULL, 1, 'texture.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-trackk', 'trackk', 'trackk.in', 'https://trackk.in', 'Trackk', 'Stock discovery and trading app for first-time Indian investors.', 'Retail investing apps usually hide complexity behind confetti; this one tries to make discovery the product. Trackk shows prompt-based Trackk Nest screeners, IPO verdicts, single-screen trading, SEBI registration, and 4.7/4.6 app-store ratings. Unlike broker clones built for power users, the bet is that first-time Indian investors need explainable search before execution. The risk is whether F&O ambition nudges beginners toward speculation.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://trackk.in", "type": "official"}, {"id": "funding_1", "label": "Moneycontrol", "url": "https://www.moneycontrol.com/news/business/funding/gen-z-investment-platform-trackk-raises-3-7-million-in-funding-from-lightspeed-info-edge-ventures-13924204.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Trackk: Stock discovery and trading app for first-time Indian investors.", "source_ids": ["official_site"]}, {"claim": "Trackk shows prompt-based Trackk Nest screeners, IPO verdicts, single-screen trading, SEBI registration, and 4.7/4.6 app-store ratings.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Finance, banking, or payments teams evaluating regulated transaction workflows.", "category": "Fintech", "differentiation": "Seed for Gen Z investing app", "why_now": "Recent source-backed funding and public product evidence make investing, wealthtech, stock discovery worth tracking."}, "risks": [{"claim": "The risk is whether F&O ambition nudges beginners toward speculation.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Seed for Gen Z investing app', 'Fintech', 'Seed', '$3.7M', NULL, NULL, NULL, 'China / Asia', 'investing,wealthtech,stock discovery,fintech,india', 'Lightspeed', NULL, 1, 'trackk.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-tribal', 'tribal', 'www.gotribal.ai', 'https://www.gotribal.ai/', 'Tribal', 'Metadata-native AI agents for governed enterprise app changes inside systems of record.', 'The sharp bet is that enterprise AI builders need system context before code generation. Tribal maps metadata, permissions, dependencies, and business rules, then wraps changes with approval flows, audit, impact analysis, and 10x backlog claims. Unlike vibe-coding tools, it treats governance as part of the build surface. The risk is whether every customer''s metadata graph becomes a bespoke services project.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.gotribal.ai/", "type": "official"}, {"id": "funding_1", "label": "GlobeNewswire", "url": "https://www.globenewswire.com/news-release/2026/05/20/3298634/0/en/Tribal-Raises-10M-Seed-to-Bring-Context-Aware-AI-Agents-to-Enterprise-Systems.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Tribal: Metadata-native AI agents for governed enterprise app changes inside systems of record.", "source_ids": ["official_site"]}, {"claim": "Tribal maps metadata, permissions, dependencies, and business rules, then wraps changes with approval flows, audit, impact analysis, and 10x backlog claims.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "10x faster backlog work", "why_now": "Recent source-backed funding and public product evidence make enterprise ai, metadata, salesforce worth tracking."}, "risks": [{"claim": "The risk is whether every customer''s metadata graph becomes a bespoke services project.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '10x faster backlog work', 'SaaS', 'Seed', '$10M', NULL, NULL, NULL, 'US', 'enterprise ai,metadata,salesforce,governance', 'Team8', NULL, 1, 'tribal.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-val-town', 'val-town', 'val.town', 'https://val.town', 'Val Town', 'Social website and API for writing and running code.', 'Putting running code inside a social feed sounds gimmicky until you try it. Every val is a URL, every function is deployable, and the product turns tiny scripts into shareable building blocks. That is a real bet against repo-first developer tooling. It feels closer to what Gists wanted to be than another serverless dashboard.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://val.town", "type": "official"}, {"id": "funding_1", "label": "Val Town Blog", "url": "https://blog.val.town/blog/seed/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Val Town: Social website and API for writing and running code.", "source_ids": ["official_site"]}, {"claim": "Every val is a URL, every function is deployable, and the product turns tiny scripts into shareable building blocks.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "Code as social media", "why_now": "Recent source-backed funding and public product evidence make social coding, serverless, developer tools worth tracking."}, "risks": [{"claim": "Continued tracking should verify whether the public product evidence turns into durable customer adoption beyond the currently visible surface.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, 'Code as social media', 'DevTools', 'Seed', '$5.5M', 2022, '5-10', 'Brooklyn', 'US', 'social coding,serverless,developer tools,code sharing', 'Sequoia Capital Scout, Craft Ventures, Tom Preston-Werner', '{"github": "https://github.com/val-town", "twitter": "https://x.com/valabordar", "linkedin": "https://linkedin.com/company/val-town"}', 0, 'val-town.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-vapi', 'vapi', 'vapi.ai', 'https://vapi.ai', 'Vapi', 'Voice AI infrastructure for building, deploying, and managing phone agents.', 'The smart bet is that voice agents need latency infrastructure, not another bot builder. Vapi exposes call workflows, tool integrations, guardrails, SOC 2/HIPAA/PCI posture, and claims 1B calls, 2.5M+ agents, 750K developers, and sub-500ms latency. Compared with Twilio wrappers or contact-center suites, it sells the voice runtime beneath Ring-scale support. The risk is that voice AI becomes a commodity inside every CX platform.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://vapi.ai", "type": "official"}, {"id": "funding_1", "label": "TechCrunch", "url": "https://techcrunch.com/2026/05/12/vapi-hits-500m-valuation-as-amazon-ring-chose-its-ai-platform-over-40-rivals/", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Vapi: Voice AI infrastructure for building, deploying, and managing phone agents.", "source_ids": ["official_site"]}, {"claim": "Vapi exposes call workflows, tool integrations, guardrails, SOC 2/HIPAA/PCI posture, and claims 1B calls, 2.5M+ agents, 750K developers, and sub-500ms latency.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Developers and engineering teams evaluating build, deployment, or infrastructure workflows.", "category": "DevTools", "differentiation": "1B calls on voice-agent platform", "why_now": "Recent source-backed funding and public product evidence make voice ai, ai agents, developer tools worth tracking."}, "risks": [{"claim": "The risk is that voice AI becomes a commodity inside every CX platform.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '1B calls on voice-agent platform', 'DevTools', 'Series B', '$50M', NULL, NULL, NULL, 'US', 'voice ai,ai agents,developer tools,customer support', 'Peak XV Partners', NULL, 0, 'vapi.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-vector', 'vector', 'www.vector.co', 'https://www.vector.co', 'Vector', 'Contact-level ad audiences and MCP analytics for B2B marketers.', 'The interesting choice is putting names back into ad targeting instead of hiding inside account segments. Vector shows visitor feeds, named buyer audiences, LinkedIn/Google/Reddit sync, 7.8% LinkedIn CTR, 17x ROI, and an MCP for asking campaign questions in Claude or ChatGPT. Unlike retargeting, it filters for exact ICP contacts already moving. The risk is that contact-level precision invites privacy pushback as fast as pipeline.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://www.vector.co", "type": "official"}, {"id": "funding_1", "label": "Vector", "url": "https://www.vector.co/blog/we-just-raised-10m-to-build-the-ai-platform-that-makes-marketers-superhuman", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes Vector: Contact-level ad audiences and MCP analytics for B2B marketers.", "source_ids": ["official_site"]}, {"claim": "Vector shows visitor feeds, named buyer audiences, LinkedIn/Google/Reddit sync, 7.8% LinkedIn CTR, 17x ROI, and an MCP for asking campaign questions in Claude or ChatGPT.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Business teams evaluating workflow software for a specific operating function.", "category": "SaaS", "differentiation": "$10M Series A for Vector MCP", "why_now": "Recent source-backed funding and public product evidence make b2b marketing, advertising, mcp worth tracking."}, "risks": [{"claim": "The risk is that contact-level precision invites privacy pushback as fast as pipeline.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 4, '$10M Series A for Vector MCP', 'SaaS', 'Series A', '$10M', NULL, NULL, NULL, 'US', 'b2b marketing,advertising,mcp,marketing analytics', 'SignalFire, HubSpot Ventures', NULL, 1, 'vector.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, research_json, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-wirobotics', 'wirobotics', 'corp.wirobotics.com', 'https://corp.wirobotics.com/en/product/allex', 'WIRobotics', 'Wearable and humanoid robots built from human movement data.', 'The real bet is that humanoids should learn from exoskeletons, not lab demos. WIRobotics has 3,000 WIM units sold, three CES awards, gait datasets from wearable robots, and ALLEX specs like 15-DoF hands, 0.5 mm repeatability, and 30 kg hook grip. Compared with blank-slate humanoid hype, this starts from human movement in the field. The risk is whether research platforms become durable products.', '{"verified_at": "2026-05-26", "sources": [{"id": "official_site", "label": "Official product site", "url": "https://corp.wirobotics.com/en/product/allex", "type": "official"}, {"id": "funding_1", "label": "PR Newswire", "url": "https://www.prnewswire.com/news-releases/wirobotics-secures-approximately-krw-100-billion-usd-68-million-series-b-funding-302772164.html", "type": "funding"}], "product_evidence": [{"claim": "Official product positioning describes WIRobotics: Wearable and humanoid robots built from human movement data.", "source_ids": ["official_site"]}, {"claim": "WIRobotics has 3,000 WIM units sold, three CES awards, gait datasets from wearable robots, and ALLEX specs like 15-DoF hands, 0.5 mm repeatability, and 30 kg hook grip.", "source_ids": ["official_site"]}], "market_context": {"primary_user": "Operators evaluating a specialized workflow where the product surface is visible.", "category": "Other", "differentiation": "3,000 WIM units, $68M Series B", "why_now": "Recent source-backed funding and public product evidence make robotics, wearables, humanoids worth tracking."}, "risks": [{"claim": "The risk is whether research platforms become durable products.", "basis": "VentureDex editorial assessment based on official product evidence and funding-source review."}]}', 5, '3,000 WIM units, $68M Series B', 'Other', 'Series B', '$68M', NULL, NULL, NULL, 'China / Asia', 'robotics,wearables,humanoids,physical ai', 'JB Investment', NULL, 1, 'wirobotics.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, research_json = excluded.research_json, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
