INSERT INTO weekly_issues (id, issue_number, title, editorial_intro, published_at, status) VALUES ('w-1', 1, 'The tools that changed how we build', 'For our first issue, we picked tools that changed daily software work through product choices, not just category timing. The common thread is a sharper workflow bet: keep the user''s existing context, remove one old source of friction, and make the product feel closer to the work itself.', '2026-05-25', 'published') ON CONFLICT(issue_number) DO UPDATE SET id = excluded.id, title = excluded.title, editorial_intro = excluded.editorial_intro, status = excluded.status, published_at = excluded.published_at;
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-cursor', 1, 'Strong product-shape pick: the bet is specific and visible, while the evidence boundary is product design plus sourced financing.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-linear', 2, 'High-conviction workflow pick: Linear''s product choices are clear, but quantified adoption claims should remain outside the issue unless sourced.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-perplexity', 3, 'Strong interface bet: the product change is concrete, while scale and accuracy claims need separate source-backed review.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-supabase', 4, 'Clear developer-platform pick: the Postgres-centered bet is easy to verify, while workload-level claims need case-specific evidence.');
INSERT INTO weekly_issue_startups (issue_id, startup_id, display_order, issue_note) VALUES ('w-1', 'startup-resend', 5, 'Focused workflow pick: Resend''s API and React Email pairing is concrete, while delivery-scale claims should stay source-bound.');
